_helpers.tpl.content:
{{/*
Expand the name of the chart.
*/}}
{{- define "redpoint-rpi.name" -}}
{{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Create a default fully qualified app name.
*/}}
{{- define "redpoint-rpi.fullname" -}}
{{- if .Values.fullnameOverride }}
{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- $name := default .Chart.Name .Values.nameOverride }}
{{- if contains $name .Release.Name }}
{{- .Release.Name | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- printf "%s-%s" .Release.Name $name | trunc 63 | trimSuffix "-" }}
{{- end }}
{{- end }}
{{- end }}

{{/*
Create chart name and version as used by the chart label.
*/}}
{{- define "redpoint-rpi.chart" -}}
{{- printf "%s-%s" .Chart.Name .Chart.Version | replace "+" "_" | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Common labels
*/}}
{{- define "redpoint-rpi.labels" -}}
helm.sh/chart: {{ include "redpoint-rpi.chart" . }}
{{ include "redpoint-rpi.selectorLabels" . }}
app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
app.kubernetes.io/managed-by: {{ .Release.Service }}
app.kubernetes.io/part-of: rpi
{{- end }}

{{/*
Selector labels
*/}}
{{- define "redpoint-rpi.selectorLabels" -}}
app.kubernetes.io/name: {{ .name }}
app.kubernetes.io/instance: {{ .root.Release.Name }}
{{- end }}

{{/*
Common labels for a specific component.
Usage: {{ include "redpoint-rpi.componentLabels" (dict "root" . "name" "rpi-realtimeapi" "component" "api") }}
*/}}
{{- define "redpoint-rpi.componentLabels" -}}
helm.sh/chart: {{ include "redpoint-rpi.chart" .root }}
app.kubernetes.io/name: {{ .name }}
app.kubernetes.io/instance: {{ .root.Release.Name }}
app.kubernetes.io/version: {{ .root.Values.global.deployment.images.tag | quote }}
app.kubernetes.io/managed-by: {{ .root.Release.Service }}
app.kubernetes.io/part-of: rpi
app.kubernetes.io/component: {{ .component }}
{{- end }}

{{/*
Default security context for RPI services (.NET-based)
*/}}
{{- define "redpoint-rpi.securityContext" -}}
securityContext:
  runAsUser: {{ .Values.securityContext.runAsUser }}
  runAsGroup: {{ .Values.securityContext.runAsGroup }}
  fsGroup: {{ .Values.securityContext.fsGroup }}
  runAsNonRoot: {{ .Values.securityContext.runAsNonRoot }}
  seccompProfile:
    type: RuntimeDefault
{{- end }}

{{/*
Default container security context for RPI services
*/}}
{{- define "redpoint-rpi.containerSecurityContext" -}}
securityContext:
  readOnlyRootFilesystem: {{ .readOnlyRootFilesystem | default true }}
  allowPrivilegeEscalation: false
  privileged: false
  capabilities:
    drop:
      - ALL
{{- end }}

{{/*
Topology spread constraints
Usage: {{ include "redpoint-rpi.topologySpreadConstraints" (dict "name" "rpi-realtimeapi" "root" .) }}
*/}}
{{- define "redpoint-rpi.topologySpreadConstraints" -}}
{{- if .root.Values.topologySpreadConstraints.enabled }}
topologySpreadConstraints:
  - maxSkew: {{ .root.Values.topologySpreadConstraints.maxSkew | default 1 }}
    topologyKey: {{ .root.Values.topologySpreadConstraints.topologyKey | default "topology.kubernetes.io/zone" }}
    whenUnsatisfiable: {{ .root.Values.topologySpreadConstraints.whenUnsatisfiable | default "ScheduleAnyway" }}
    labelSelector:
      matchLabels:
        app.kubernetes.io/name: {{ .name }}
{{- end }}
{{- end }}

{{/*
PreStop lifecycle hook for graceful shutdown
*/}}
{{- define "redpoint-rpi.preStopHook" -}}
lifecycle:
  preStop:
    exec:
      command: ["/bin/sh", "-c", "sleep 10"]
{{- end }}

{{/*
Standard probe configuration
Usage: {{ include "redpoint-rpi.livenessProbe" (dict "probes" .Values.realtimeapi "path" "/health") }}
*/}}
{{- define "redpoint-rpi.livenessProbe" -}}
livenessProbe:
  httpGet:
    path: {{ .path | default "/health" }}
    port: 8080
  initialDelaySeconds: {{ .probes.livenessProbe.initialDelaySeconds }}
  periodSeconds: {{ .probes.livenessProbe.periodSeconds }}
  failureThreshold: {{ .probes.livenessProbe.failureThreshold }}
  timeoutSeconds: {{ .probes.livenessProbe.timeoutSeconds }}
{{- end }}

{{- define "redpoint-rpi.readinessProbe" -}}
readinessProbe:
  httpGet:
    path: {{ .path | default "/health/ready" }}
    port: 8080
  initialDelaySeconds: {{ .probes.readinessProbe.initialDelaySeconds }}
  periodSeconds: {{ .probes.readinessProbe.periodSeconds }}
  failureThreshold: {{ .probes.readinessProbe.failureThreshold }}
  timeoutSeconds: {{ .probes.readinessProbe.timeoutSeconds }}
{{- end }}

{{- define "redpoint-rpi.startupProbe" -}}
startupProbe:
  httpGet:
    path: {{ .path | default "/health" }}
    port: 8080
  initialDelaySeconds: {{ .probes.startupProbe.initialDelaySeconds }}
  failureThreshold: {{ .probes.startupProbe.failureThreshold }}
  periodSeconds: {{ .probes.startupProbe.periodSeconds }}
  timeoutSeconds: {{ .probes.startupProbe.timeoutSeconds }}
{{- end }}

{{/*
Image pull secrets
*/}}
{{- define "redpoint-rpi.imagePullSecrets" -}}
{{- if .Values.global.deployment.images.imagePullSecret.enabled }}
imagePullSecrets:
  - name: {{ .Values.global.deployment.images.imagePullSecret.name }}
{{- end }}
{{- end }}

{{/*
Node selector
*/}}
{{- define "redpoint-rpi.nodeSelector" -}}
{{- if .Values.nodeSelector.enabled }}
nodeSelector:
  {{ .Values.nodeSelector.key }}: {{ .Values.nodeSelector.value }}
{{- end }}
{{- end }}

{{/*
Tolerations
*/}}
{{- define "redpoint-rpi.tolerations" -}}
{{- if .Values.tolerations.enabled }}
tolerations:
  - effect: {{ .Values.tolerations.effect }}
    key: {{ .Values.tolerations.key }}
    operator: {{ .Values.tolerations.operator }}
    value: {{ .Values.tolerations.value }}
{{- end }}
{{- end }}

cm-odbc.yaml.content:
{{- if .Values.databases.datawarehouse.autoCreateSecrets }}
apiVersion: v1
kind: ConfigMap
metadata:
  name: odbc-config
data:
  odbc2.ini: |
    [ODBC]
    Trace=no

    [ODBC Data Sources]
    {{- if .Values.databases.datawarehouse.redshift.enabled }}
    {{- range .Values.databases.datawarehouse.redshift.connections }}
    {{ .name }}=Amazon Redshift DSN 64=Amazon Redshift (x64)
    {{- end }}
    {{- end }}

    {{- if .Values.databases.datawarehouse.bigquery.enabled }}
    {{- range .Values.databases.datawarehouse.bigquery.connections }}
    {{ .name }}=Simba ODBC Driver for Google BigQuery 64-bit
    {{- end }}
    {{- end }}

    {{- if .Values.databases.datawarehouse.databricks.enabled }}
    {{- range .Values.databases.datawarehouse.databricks.connections }}
    {{ .name }}=Simba Apache Spark ODBC Connector
    {{- end }}
    {{- end }}

    {{- if .Values.databases.datawarehouse.redshift.enabled }}
    {{- range .Values.databases.datawarehouse.redshift.connections }}

    [{{ .name }}]
    Description=Amazon Redshift ODBC Driver for {{ .name }}
    Driver=/app/odbc-lib/redshift/lib/libamazonredshiftodbc64.so
    Server={{ .server }}
    Port={{ .port }}
    Database={{ .database }}
    UID={{ .username }}
    PWD={{ .password }}
    locale=en-US
    {{- end }}
    {{- end }}

    {{- if .Values.databases.datawarehouse.bigquery.enabled }}
    {{- range .Values.databases.datawarehouse.bigquery.connections }}

    [{{ .name }}]
    Description=Simba ODBC Driver for Google BigQuery (64-bit) DSN
    Driver=/app/odbc-lib/bigquery/SimbaODBCDriverforGoogleBigQuery64/lib/libgooglebigqueryodbc_sb64.so
    Catalog={{ .projectId }}
    SQLDialect={{ .sqlDialect }}
    AllowLargeResults={{ .allowLargeResults }}
    LargeResultsDataSetId={{ .largeResultsDataSetId }}
    LargeResultsTempTableExpirationTime={{ .largeResultsTempTableExpirationTime }}
    OAuthMechanism={{ .OAuthMechanism }}
    Email={{ .serviceAccountEmail }}
    KeyFilePath={{ .ConfigMapFilePath }}/{{ .keyName }}
    {{- end }}
    {{- end }}

    {{- if .Values.databases.datawarehouse.databricks.enabled }}
    {{- range .Values.databases.datawarehouse.databricks.connections }}

    [{{ .name }}]
    Driver=/app/odbc-lib/simba/spark/lib/libsparkodbc_sb64.so
    SparkServerType=3
    Host={{ .host }}
    Port={{ .port }}
    Schema={{ .schema }}
    SSL=1
    Min_TLS=1.2 
    ThriftTransport=2
    AuthMech={{ .authMechanism }}
    UID={{ .username }}
    PWD={{ .password }}
    TrustedCerts=/app/odbc-lib/simba/spark/lib/cacerts.pem
    UseSystemTrustStore=0
    HTTPPath={{ .httpPath }}
    {{- end }}
    {{- end }}
{{- end }}

deploy-callbackapi.yaml.content:
{{- if .Values.callbackapi.serviceAccount.enabled }}
{{- if .Values.callbackapi.enabled }}
apiVersion: v1
kind: ServiceAccount
metadata:
  name: rpi-callbackapi
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-callbackapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
  {{- if eq .Values.global.deployment.platform "azure" }}
  {{- if .Values.cloudIdentity.enabled }}
  {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
  annotations:
    azure.workload.identity/client-id: {{ .Values.cloudIdentity.azureSettings.managedIdentityClientId | quote }}
  {{- end }}
  {{- end }}
  {{- end }}
  {{- if eq .Values.global.deployment.platform "google" }}
  {{- if .Values.cloudIdentity.enabled }}
  {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
  annotations:
    iam.gke.io/gcp-service-account: {{ .Values.cloudIdentity.googleSettings.serviceAccountEmail | quote }}
  {{- end }}
  {{- end }}
  {{- end }}
{{- end }}
{{- end }}

---
{{- if .Values.callbackapi.podDisruptionBudget.enabled }}
apiVersion: policy/v1
kind: PodDisruptionBudget
metadata:
  name: rpi-callbackapi
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-callbackapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  maxUnavailable: {{ .Values.callbackapi.podDisruptionBudget.maxUnavailable }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-callbackapi
{{- end }}

---
{{- if .Values.callbackapi.enabled }}
{{- if eq .Values.callbackapi.type "rollout" }}
apiVersion: v1
kind: Service
metadata:
  name: rpi-callbackapi-preview
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-callbackapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  ports:
  - name: http
    port: {{ .Values.callbackapi.service.port }}
    protocol: TCP
    targetPort: 8080
  selector:
    app.kubernetes.io/name: rpi-callbackapi
{{- end }}
{{- end }}
   
---
{{- if .Values.callbackapi.enabled }}
apiVersion: v1
kind: Service
metadata:
  name: rpi-callbackapi
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-callbackapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  ports:
  - name: http
    port: {{ .Values.callbackapi.service.port }}
    protocol: TCP
    targetPort: 8080
  selector:
    app.kubernetes.io/name: rpi-callbackapi

---
{{- if eq .Values.callbackapi.type "rollout" }}
apiVersion: argoproj.io/v1alpha1
kind: Rollout
{{- end }}
{{- if eq .Values.callbackapi.type "deployment" }}
apiVersion: apps/v1
kind: Deployment
{{- end }}
metadata:
  name: rpi-callbackapi
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-callbackapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
    app: rpi-callbackapi
    {{- with .Values.callbackapi.customLabels }}
    {{- toYaml . | nindent 4 }} 
    {{- end }}
spec:
  {{- if not .Values.callbackapi.autoscaling.enabled }}
  replicas: {{ .Values.callbackapi.replicas }}
  {{- end }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-callbackapi
  {{- if eq .Values.callbackapi.type "rollout" }}
  strategy:
    blueGreen:
      activeService: rpi-callbackapi
      previewService: rpi-callbackapi-preview
      autoPromotionEnabled: {{ .Values.callbackapi.rollout.autoPromotionEnabled }}
  revisionHistoryLimit: {{ .Values.callbackapi.rollout.revisionHistoryLimit }}
  {{- end }}
  template:
    metadata:
      labels:
        app.kubernetes.io/name: rpi-callbackapi
        app.kubernetes.io/instance: {{ .Release.Name }}
        app.kubernetes.io/part-of: rpi
        app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
        {{- with .Values.callbackapi.customLabels }}
        {{- toYaml . | nindent 8 }} 
        {{- end }}
        {{- if eq .Values.global.deployment.platform "azure" }}
        {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
        azure.workload.identity/use: "true"
        {{- end }}
        {{- end }}
      annotations:
        {{- with .Values.callbackapi.customAnnotations }}
        {{- toYaml . | nindent 8 }}
        {{- end }}
        {{- if .Values.callbackapi.customMetrics.enabled }}
        prometheus.io/scrape: {{ .Values.callbackapi.customMetrics.prometheus_scrape | quote }}
        prometheus.io/port: "8080"
        prometheus.io/path: "/metrics"
        {{- end }}
    spec:
      {{- if .Values.global.deployment.images.imagePullSecret.enabled }}
      imagePullSecrets:
      - name: {{ .Values.global.deployment.images.imagePullSecret.name }}
      {{- end }}
      terminationGracePeriodSeconds: {{ .Values.callbackapi.terminationGracePeriodSeconds }}
      serviceAccountName: rpi-callbackapi
      {{- if .Values.securityContext.enabled }}
      securityContext:
        runAsUser: {{ .Values.securityContext.runAsUser }}
        runAsGroup: {{ .Values.securityContext.runAsGroup }}
        fsGroup: {{ .Values.securityContext.fsGroup }}
        runAsNonRoot: {{ .Values.securityContext.runAsNonRoot }}
      {{- end }}
      affinity:
        podAntiAffinity:
          preferredDuringSchedulingIgnoredDuringExecution:
            - weight: 100
              podAffinityTerm:
                labelSelector:
                  matchLabels:
                    app.kubernetes.io/name: rpi-callbackapi
                topologyKey: kubernetes.io/hostname
      {{- if .Values.topologySpreadConstraints.enabled }}
      topologySpreadConstraints:
        - maxSkew: {{ .Values.topologySpreadConstraints.maxSkew }}
          topologyKey: {{ .Values.topologySpreadConstraints.topologyKey }}
          whenUnsatisfiable: {{ .Values.topologySpreadConstraints.whenUnsatisfiable }}
          labelSelector:
            matchLabels:
              app.kubernetes.io/name: rpi-callbackapi
      {{- end }}
      containers:
      - env:
        - name: Logging__LogLevel__Default
          value: {{ .Values.callbackapi.logging.default | quote }}
        - name: Logging__Database__LogLevel__Default
          value: {{ .Values.callbackapi.logging.database | quote }}
        - name: Logging__Database__RPITrace
          value: {{ .Values.callbackapi.logging.rpiTrace | quote }}
        - name: Logging__Database__RPIError
          value: {{ .Values.callbackapi.logging.rpiError | quote }}
        - name: Logging__Console__LogLevel__Default
          value: {{ .Values.callbackapi.logging.Console | quote }}
        - name: CallbackServiceConfig__QueueEnabled
          value: "true"
        - name: RPI__DateTimeSource
          value: {{ .Values.databases.operational.dateTimeSource | quote }}
        {{- if .Values.diagnosticsMode.copytoAzureBlob.enabled }}
        - name: RPI__Diagnostics__CopyToAzure__IsEnabled
          value: "true"
        - name: RPI__Diagnostics__CopyToAzure__StorageAccount
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.accountName | quote }}
        - name: RPI__Diagnostics__CopyToAzure__AccessKey
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: CopyToAzureBlobAccessKey
        - name: RPI__Diagnostics__CopyToAzure__ContainerName
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.containerName | quote }}
        - name: RPI__Diagnostics__CopyToAzure__BlobServiceEndpoint
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.blobServiceEndpoint | quote }}
        - name: RPI__Diagnostics__CopyToAzure__EnableCdn
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.enableCdn | quote }}
        - name: RPI__Diagnostics__CopyToAzure__AzureUseDataLakeStorageGen2
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.UseDataLakeStorageGen2 | quote }}
        {{- end }}
        {{- if .Values.diagnosticsMode.copytoSftp.enabled }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPHost
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpHost | quote }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPUsername
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpUsername | quote }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPPassword
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: CopyToSFTPSecureFTPPassword
        - name: RPI__Diagnostics__CopyToSFTP__PortNumber
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpPort | quote }}
        - name: RPI__Diagnostics__UseSFTP
          value: "true"
        - name: RPI__Diagnostics__CopyToSFTP__IsEnabled
          value: "true"
        {{- end }}
        {{- if .Values.diagnosticsMode.dotNetTools.enabled }}
        - name: DOTNET_BUNDLE_EXTRACT_BASE_DIR
          value: {{ .Values.diagnosticsMode.dotNetTools.extractionBaseDir | quote }} 
        - name: RPI__Diagnostics__UseDotNetTools__Path
          value: {{  .Values.diagnosticsMode.dotNetTools.path  | quote }}
        - name: RPI__Diagnostics__UseDotNetTools__UseCounters
          value: {{ .Values.diagnosticsMode.dotNetTools.useCounters | quote }}
        - name: RPI__Diagnostics__UseDotNetTools__CounterProviderList
          value: '["System.Runtime", "Microsoft.Extensions.Diagnostics.ResourceMonitoring"]'
        - name: RPI__Diagnostics__UseDotNetTools__UseGcDump
          value: {{ .Values.diagnosticsMode.dotNetTools.useGcDump | quote }}
        {{- end }}
        {{- if eq .Values.global.deployment.platform "azure" }}
        - name: CallbackServiceConfig__QueueProvider__CallbackServiceQueuePath
          value: {{ .Values.realtimeapi.queueProvider.queueNames.callbackServiceQueuePath | quote }}
        {{- end }}
        {{- if eq .Values.global.deployment.platform "amazon" }}
        - name: CallbackServiceConfig__QueueProvider__CallbackServiceQueuePath
          value: {{ .Values.realtimeapi.queueProvider.queueNames.callbackServiceQueuePath | quote }}
        {{- end }}
        {{- if eq .Values.global.deployment.platform "selfhosted" }}
        - name: CallbackServiceConfig__QueueProvider__CallbackServiceQueuePath
          value: {{ .Values.realtimeapi.queueProvider.queueNames.callbackServiceQueuePath | quote }}
        {{- end }}
        {{- if eq .Values.global.deployment.platform "google" }}
        - name: CallbackServiceConfig__QueueProvider__CallbackServiceQueuePath
          value: "{{ .Values.realtimeapi.queueProvider.queueNames.callbackServiceQueuePath }}/{{ .Values.realtimeapi.queueProvider.queueNames.callbackServiceQueuePath }}"
        {{- end }}
        - name: CallbackServiceConfig__QueueProvider__CallbackServiceQueueSettings__AllowedHosts
          value: "*"
        - name: CallbackServiceConfig__QueueProvider__ChannelLabel
          value: {{ .Values.callbackapi.channelLabel | quote }}
        {{- if .Values.cloudIdentity.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Azure" }}
        {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
        - name: CloudIdentity__Azure__CredentialType
          value: "AzureIdentity"
        - name: CloudIdentity__Azure__UseADTokenForDatabaseConnection
          value: {{ .Values.cloudIdentity.azureSettings.UseADTokenForDatabaseConnection | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Azure" }}
        - name: KeyVault__Provider
          value: "Azure"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        - name: KeyVault__AzureSettings__VaultURI
          value: {{ .Values.cloudIdentity.azureSettings.vaultUri | quote }}
        - name: KeyVault__AzureSettings__AppSettingsVaultURI
          value: {{ .Values.cloudIdentity.azureSettings.appSettingsVaultUri | quote }}
        - name: KeyVault__AzureSettings__ConfigurationReloadIntervalSeconds
          value: {{ .Values.cloudIdentity.secretsManagement.ConfigurationReloadIntervalSeconds | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.global.deployment.platform "google" }}
        {{- if eq .Values.cloudIdentity.googleSettings.credentialsType "serviceAccount" }}
        - name: GOOGLE_APPLICATION_CREDENTIALS 
          value: "{{ .Values.cloudIdentity.googleSettings.ConfigMapFilePath }}/{{ .Values.cloudIdentity.googleSettings.keyName }}"
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Google" }}
        - name: KeyVault__Provider
          value: "Google"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        {{- if eq .Values.cloudIdentity.amazonSettings.credentialsType "accessKey" }}
        - name: AWS_ACCESS_KEY_ID
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Access_Key_ID
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_SECRET_ACCESS_KEY
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Secret_Access_Key
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_REGION
          value: {{ .Values.cloudIdentity.amazonSettings.region | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        - name: KeyVault__Provider
          value: "Amazon"
        - name: KeyVault__AmazonSettings__AppSettingsTag
          value: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.secretTagKey | quote }}
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "sqlserver" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "sqlserveronvm" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "postgresql" }}
