            {{- end }}
        {{- end }}
        imagePullPolicy: {{  .Values.global.deployment.images.imagePullPolicy }}
        env:
        - name: Logging__LogLevel__Default
          value: {{ .Values.deploymentapi.logging.default | quote }}
        - name: Logging__Database__LogLevel__Default
          value: {{ .Values.deploymentapi.logging.database | quote }}
        - name: Logging__Database__RPITrace
          value: {{ .Values.deploymentapi.logging.rpiTrace | quote }}
        - name: Logging__Database__RPIError
          value: {{ .Values.deploymentapi.logging.rpiError | quote }}
        - name: Logging__Console__LogLevel__Default
          value: {{ .Values.deploymentapi.logging.Console | quote }}
        - name: ClusterEnvironment__OperationalDatabase__PulseDatabaseName
          value: {{ .Values.databases.operational.pulse_database_name | quote }}
        - name: ClusterEnvironment__OperationalDatabase__LoggingDatabaseName
          value: {{ .Values.databases.operational.pulse_logging_database_name | quote }}
        - name: ClusterEnvironment__OperationalDatabase__ConnectionSettings__Server
          value: {{ .Values.databases.operational.server_host | quote }}
        - name: ClusterEnvironment__OperationalDatabase__ConnectionSettings__IsUsingCredentials
          value: "true"
        - name: ClusterEnvironment__OperationalDatabase__ConnectionSettings__DatabaseSchema
          value: {{ .Values.databases.operational.databaseSchema | quote }}
        {{- if .Values.databases.operational.encrypt }}
        - name: ClusterEnvironment__OperationalDatabase__ConnectionSettings__SQLServerSettings__Encrypt
          value: "true"
        {{- end }}
        - name: ClusterEnvironment__OperationalDatabase__ConnectionSettings__SQLServerSettings__TrustServerCertificate
          value: "true"
        {{- if .Values.cloudIdentity.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Azure" }}
        {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
        - name: CloudIdentity__Azure__CredentialType
          value: "AzureIdentity"
        - name: CloudIdentity__Azure__UseADTokenForDatabaseConnection
          value: {{ .Values.cloudIdentity.azureSettings.UseADTokenForDatabaseConnection | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Azure" }}
        - name: KeyVault__Provider
          value: "Azure"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        - name: KeyVault__AzureSettings__VaultURI
          value: {{ .Values.cloudIdentity.azureSettings.vaultUri | quote }}
        - name: KeyVault__AzureSettings__AppSettingsVaultURI
          value: {{ .Values.cloudIdentity.azureSettings.appSettingsVaultUri | quote }}
        - name: KeyVault__AzureSettings__ConfigurationReloadIntervalSeconds
          value: {{ .Values.cloudIdentity.secretsManagement.ConfigurationReloadIntervalSeconds | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.global.deployment.platform "google" }}
        {{- if eq .Values.cloudIdentity.googleSettings.credentialsType "serviceAccount" }}
        - name: GOOGLE_APPLICATION_CREDENTIALS 
          value: "{{ .Values.cloudIdentity.googleSettings.ConfigMapFilePath }}/{{ .Values.cloudIdentity.googleSettings.keyName }}"
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Google" }}
        - name: KeyVault__Provider
          value: "Google"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        {{- if eq .Values.cloudIdentity.amazonSettings.credentialsType "accessKey" }}
        - name: AWS_ACCESS_KEY_ID
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Access_Key_ID
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_SECRET_ACCESS_KEY
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Secret_Access_Key
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_REGION
          value: {{ .Values.cloudIdentity.amazonSettings.region | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        - name: KeyVault__Provider
          value: "Amazon"
        - name: KeyVault__AmazonSettings__AppSettingsTag
          value: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.secretTagKey | quote }}
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "sqlserver" }}
        {{- if eq .Values.global.deployment.platform "amazon" }}
        - name: ClusterEnvironment__OperationalDatabase__DatabaseType
          value: "AmazonRDSSQL"
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "sqlserver" }}
        {{- if eq .Values.global.deployment.platform "azure" }}
        - name: ClusterEnvironment__OperationalDatabase__DatabaseType
          value: "AzureSQLDatabase"
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "sqlserver" }}
        {{- if eq .Values.global.deployment.platform "google" }}
        - name: ClusterEnvironment__OperationalDatabase__DatabaseType
          value: "GoogleCloudSQL"
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "postgresql" }}
        - name: ClusterEnvironment__OperationalDatabase__DatabaseType
          value: "PostgreSQL"
        - name: ClusterEnvironment__OperationalDatabase__ConnectionSettings__Port
          value: "5432"
        {{- end }}
        {{- if eq .Values.databases.operational.provider "sqlserveronvm" }}
        - name: ClusterEnvironment__OperationalDatabase__DatabaseType
          value: "SQLServer"
        {{- end }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: ClusterEnvironment__OperationalDatabase__ConnectionSettings__Username
          value: {{ .Values.databases.operational.server_username | quote }}
        - name: ClusterEnvironment__OperationalDatabase__ConnectionSettings__Password
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: Operations_Database_Server_Password
        {{- end }}
        ports:
        - containerPort: 8080
          name: web-port
          protocol: TCP
        {{- if .Values.deploymentapi.resources.enabled }}
        resources:
          {{- if and .Values.deploymentapi.resources.limits (ne .Values.deploymentapi.resources.limits.enabled false) }}
          limits:
            {{- with .Values.deploymentapi.resources.limits.cpu }}
            cpu: {{ . }}
            {{- end }}
            {{- with .Values.deploymentapi.resources.limits.memory }}
            memory: {{ . }}
            {{- end }}
          {{- end }}
          {{- if and .Values.deploymentapi.resources.requests (ne .Values.deploymentapi.resources.requests.enabled false) }}
          requests:
            {{- with .Values.deploymentapi.resources.requests.cpu }}
            cpu: {{ . }}
            {{- end }}
            {{- with .Values.deploymentapi.resources.requests.memory }}
            memory: {{ . }}
            {{- end }}
        {{- end }}
        {{- end }}
        volumeMounts:
          - name: tempstore
            mountPath: /tmp
          {{- if .Values.deploymentapi.templateTenant.useTemplateFiles }}
          - name: templatetenantfiles
            mountPath: {{ .Values.deploymentapi.templateTenant.templateTenantFilesPath | quote }}
          {{- end }}
      volumes:
        - name: tempstore
          emptyDir: {}
        {{- if .Values.deploymentapi.templateTenant.useTemplateFiles }}
        - name: templatetenantfiles
          persistentVolumeClaim:
            claimName: {{ .Values.deploymentapi.templateTenant.volumeClaimName | quote }}
        {{- end }}
      {{- if .Values.nodeSelector.enabled }}
      nodeSelector:
        {{ .Values.nodeSelector.key }}: {{ .Values.nodeSelector.value }}
      {{- end }}
      {{- if .Values.tolerations.enabled }}
      tolerations:
        - effect: NoSchedule
          key: {{ .Values.nodeSelector.key }}
          operator: Equal
          value: {{ .Values.nodeSelector.value }}
      {{- end }}
{{- end }}

deploy-executionservice.yaml.content:
{{- if .Values.executionservice.serviceAccount.enabled }}
apiVersion: v1
kind: ServiceAccount
metadata:
  name: rpi-executionservice
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-executionservice
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
  {{- if eq .Values.global.deployment.platform "azure" }}
  {{- if .Values.cloudIdentity.enabled }}
  {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
  annotations:
    azure.workload.identity/client-id: {{ .Values.cloudIdentity.azureSettings.managedIdentityClientId }}
  {{- end }}
  {{- end }}
  {{- end }}
  {{- if eq .Values.global.deployment.platform "google" }}
  {{- if .Values.cloudIdentity.enabled }}
  {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
  annotations:
    iam.gke.io/gcp-service-account: {{ .Values.cloudIdentity.googleSettings.serviceAccountEmail | quote }}
  {{- end }}
  {{- end }}
  {{- end }}
{{- end }}

---
{{- if .Values.executionservice.podDisruptionBudget.enabled }}
apiVersion: policy/v1
kind: PodDisruptionBudget
metadata:
  name: rpi-executionservice
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-executionservice
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  maxUnavailable: {{ .Values.executionservice.podDisruptionBudget.maxUnavailable }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-executionservice
{{- end }}

---
{{- if .Values.executionservice.enabled }}
{{- if eq .Values.executionservice.type "rollout" }}
apiVersion: v1
kind: Service
metadata:
  name: rpi-executionservice-preview
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-executionservice
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  ports:
  - name: http
    port: {{ .Values.executionservice.service.port }}
    protocol: TCP
    targetPort: 8080
  selector:
    app.kubernetes.io/name: rpi-executionservice
{{- end }}
{{- end }}

---
{{- if .Values.executionservice.enabled }}
apiVersion: v1
kind: Service
metadata:
  name: rpi-executionservice
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-executionservice
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  ports:
  - name: http
    port: {{ .Values.executionservice.service.port }}
    protocol: TCP
    targetPort: 8080
  selector:
    app.kubernetes.io/name: rpi-executionservice

---
{{- if eq .Values.executionservice.type "rollout" }}
apiVersion: argoproj.io/v1alpha1
kind: Rollout
{{- end }}
{{- if eq .Values.executionservice.type "deployment" }}
apiVersion: apps/v1
kind: Deployment
{{- end }}
metadata:
  name: rpi-executionservice
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-executionservice
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
    {{- with .Values.executionservice.customLabels }}
    {{- toYaml . | nindent 4 }} 
    {{- end }}
spec:
  {{- if not .Values.executionservice.autoscaling.enabled }}
  replicas: {{ .Values.executionservice.replicas }}
  {{- end }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-executionservice
  {{- if eq .Values.executionservice.type "rollout" }}
  strategy:
    blueGreen:
      activeService: rpi-executionservice
      previewService: rpi-executionservice-preview
      autoPromotionEnabled: {{ .Values.executionservice.rollout.autoPromotionEnabled }}
  revisionHistoryLimit: {{ .Values.executionservice.rollout.revisionHistoryLimit }}
  {{- end }}
  template:
    metadata:
      labels:
        app.kubernetes.io/name: rpi-executionservice
        app.kubernetes.io/instance: {{ .Release.Name }}
        app.kubernetes.io/part-of: rpi
        app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
        {{- with .Values.executionservice.customLabels }}
        {{- toYaml . | nindent 8 }} 
        {{- end }}
        {{- if eq .Values.global.deployment.platform "azure" }}
        {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
        azure.workload.identity/use: "true"
        {{- end }}
        {{- end }}
      annotations:
        {{- with .Values.executionservice.customAnnotations }}
        {{- toYaml . | nindent 8 }}
        {{- end }}
        {{- if .Values.executionservice.customMetrics.enabled }}
        prometheus.io/scrape: {{ .Values.executionservice.customMetrics.prometheus_scrape | quote }}
        prometheus.io/port: "8080"
        prometheus.io/path: "/metrics"
        {{- end }}
    spec:
      {{- if .Values.global.deployment.images.imagePullSecret.enabled }}
      imagePullSecrets:
      - name: {{ .Values.global.deployment.images.imagePullSecret.name }}
      {{- end }}
      {{- if eq .Values.executionservice.autoscaling.type "keda" }}
      terminationGracePeriodSeconds: {{ .Values.executionservice.autoscaling.kedaScaledObject.terminationGracePeriodSeconds }}
      {{- end }}
      {{- if eq .Values.executionservice.autoscaling.type "hpa" }}
      terminationGracePeriodSeconds: {{ .Values.executionservice.terminationGracePeriodSeconds }}
      {{- end }}
      serviceAccountName: rpi-executionservice
      {{- if .Values.securityContext.enabled }}
      securityContext:
        runAsUser: {{ .Values.securityContext.runAsUser }}
        runAsGroup: {{ .Values.securityContext.runAsGroup }}
        fsGroup: {{ .Values.securityContext.fsGroup }}
        runAsNonRoot: {{ .Values.securityContext.runAsNonRoot }}
        supplementalGroups:
          {{- with .Values.securityContext.supplementalGroups }}
          {{- toYaml . | nindent 10 }}
          {{- end }}
      {{- end }}
      affinity:
        podAntiAffinity:
          preferredDuringSchedulingIgnoredDuringExecution:
            - weight: 100
              podAffinityTerm:
                labelSelector:
                  matchLabels:
                    app.kubernetes.io/name: rpi-executionservice
                topologyKey: kubernetes.io/hostname
      {{- if .Values.topologySpreadConstraints.enabled }}
      topologySpreadConstraints:
        - maxSkew: {{ .Values.topologySpreadConstraints.maxSkew }}
          topologyKey: {{ .Values.topologySpreadConstraints.topologyKey }}
          whenUnsatisfiable: {{ .Values.topologySpreadConstraints.whenUnsatisfiable }}
          labelSelector:
            matchLabels:
              app.kubernetes.io/name: rpi-executionservice
      {{- end }}
      containers:
      - env:
        - name: Logging__LogLevel__Default
          value: {{ .Values.executionservice.logging.default | quote }}
        - name: Logging__Database__LogLevel__Default
          value: {{ .Values.executionservice.logging.database | quote }}
        - name: Logging__Database__RPITrace
          value: {{ .Values.executionservice.logging.rpiTrace | quote }}
        - name: Logging__Database__RPIError
          value: {{ .Values.executionservice.logging.rpiError | quote }}
        - name: Logging__Console__LogLevel__Default
          value: {{ .Values.executionservice.logging.Console | quote }}
        - name: RPI__DateTimeSource
          value: {{ .Values.databases.operational.dateTimeSource | quote }}
        - name: ODBCINI
          value: "/odbc-config/odbc.ini"
        - name: RPIExecution__MaxSmartAssetInstancesForOfferCodes
          value: {{ .Values.executionservice.jobExecution.maxSmartAssetInstancesForOfferCodes | quote }}
        {{- range .Values.executionservice.extraEnvs }}
        {{- if .enabled }}
        - name: {{ .name }}
          value: {{ quote .value }}
        {{- end }}
        {{- end }}
        {{- if .Values.executionservice.internalCache.enabled }}
        - name: InternalCache__IsEnabled
          value: "true"
        - name: InternalCache__BackupToOpsDBInterval
          value: {{ .Values.executionservice.internalCache.backupToOpsDBInterval | quote }}
        - name: InternalCache__MaxNumberRetries
          value: {{ .Values.executionservice.internalCache.maxNumberRetries | quote }}
        - name: InternalCache__MaxRetryDelay
          value: {{ .Values.executionservice.internalCache.maxRetryDelay | quote }}
        - name: InternalCache__FailOnPrimaryDataLoss
          value: {{ .Values.executionservice.internalCache.failOnPrimaryDataLoss | quote }}
        - name: InternalCache__FailOnCacheConnectionError
          value: {{ .Values.executionservice.internalCache.failOnCacheConnectionError | quote }}
        {{- end }}
        {{- if .Values.executionservice.internalCache.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: InternalCache__RedisSettings__IPAddress
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: ExecutionService_RedisCache_ConnectionString
        {{- end }}
        {{- end }}
        {{- if .Values.diagnosticsMode.copytoAzureBlob.enabled }}
        - name: RPI__Diagnostics__CopyToAzure__IsEnabled
          value: "true"
        - name: RPI__Diagnostics__CopyToAzure__StorageAccount
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.accountName | quote }}
        - name: RPI__Diagnostics__CopyToAzure__AccessKey
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: CopyToAzureBlobAccessKey
        - name: RPI__Diagnostics__CopyToAzure__ContainerName
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.containerName | quote }}
        - name: RPI__Diagnostics__CopyToAzure__BlobServiceEndpoint
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.blobServiceEndpoint | quote }}
        - name: RPI__Diagnostics__CopyToAzure__EnableCdn
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.enableCdn | quote }}
        - name: RPI__Diagnostics__CopyToAzure__AzureUseDataLakeStorageGen2
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.UseDataLakeStorageGen2 | quote }}
        {{- end }}
        {{- if .Values.diagnosticsMode.copytoSftp.enabled }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPHost
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpHost | quote }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPUsername
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpUsername | quote }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPPassword
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: CopyToSFTPSecureFTPPassword
        - name: RPI__Diagnostics__CopyToSFTP__PortNumberNumber
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpPort | quote }}
        - name: RPI__Diagnostics__UseSFTP
          value: "true"
        - name: RPI__Diagnostics__CopyToSFTP__IsEnabled
          value: "true"
        {{- end }}
        {{- if .Values.diagnosticsMode.dotNetTools.enabled }}
        - name: DOTNET_BUNDLE_EXTRACT_BASE_DIR
          value: {{ .Values.diagnosticsMode.dotNetTools.extractionBaseDir | quote }} 
        - name: RPI__Diagnostics__UseDotNetTools__Path
          value: {{  .Values.diagnosticsMode.dotNetTools.path  | quote }}
        - name: RPI__Diagnostics__UseDotNetTools__UseCounters
          value: {{ .Values.diagnosticsMode.dotNetTools.useCounters | quote }}
        - name: RPI__Diagnostics__UseDotNetTools__CounterProviderList
          value: '["System.Runtime", "Microsoft.Extensions.Diagnostics.ResourceMonitoring"]'
        - name: RPI__Diagnostics__UseDotNetTools__UseGcDump
          value: {{ .Values.diagnosticsMode.dotNetTools.useGcDump | quote }}
        {{- end }}
        - name: RPIExecution__InternalAddress
          value: {{ .Values.executionservice.jobExecution.internalAddress | quote }}
        - name: RPIExecution__AuditTaskEvents
          value: {{ .Values.executionservice.jobExecution.auditTaskEvents | quote }}
        - name: RPIExecution__MaxThreadsPerExecutionService
          value: {{ .Values.executionservice.jobExecution.maxThreadsPerExecutionService | quote }}
        - name: RPIExecution__ExecutionShutdownWaitForActivity
          value: {{ .Values.executionservice.jobExecution.executionShutdownWaitForActivity | quote }}
        - name: RPIExecution__OverrideCustomSQLReservedWords
          value: {{ .Values.executionservice.jobExecution.overrideCustomSQLReservedWords | quote }}
        - name: RPIExecution__RPDMOApiPrefixUri
          value: {{ .Values.executionservice.jobExecution.rpdmOApiPrefixUri | quote }}
        - name: RPIExecution__RPDMOApiRequestTimeout
          value: {{ .Values.executionservice.jobExecution.rpdmOApiRequestTimeout | quote }}
        - name: RPIExecution__TaskTimeout
          value: {{ .Values.executionservice.jobExecution.taskTimeout | quote }}
        - name: RPIExecution__TriggerCheckCriteriaInterval
          value: {{ .Values.executionservice.jobExecution.triggerCheckCriteriaInterval | quote }}
        - name: RPIExecution__TriggersMaxDaysInactive
          value: {{ .Values.executionservice.jobExecution.triggersMaxDaysInactive | quote }}
        - name: RPIExecution__DefaultMaintenanceModeBufferTime
          value: {{ .Values.executionservice.jobExecution.defaultMaintenanceModeBufferTime | quote }}
        - name: RPIExecution__WorkflowPrioritization__Enabled
          value: {{ .Values.executionservice.jobExecution.workflowPrioritization.enabled | quote }}
        - name: RPIExecution__WorkflowPrioritization__MaxConcurrentWorkflowActivities
          value: {{ .Values.executionservice.jobExecution.workflowPrioritization.maxConcurrentWorkflowActivities | quote }}
        - name: RPIExecution__WorkflowPrioritization__MaximumQueueTime
          value: {{ .Values.executionservice.jobExecution.workflowPrioritization.maximumQueueTime | quote }}
        {{- if .Values.cloudIdentity.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Azure" }}
        {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
        - name: CloudIdentity__Azure__CredentialType
          value: "AzureIdentity"
        - name: CloudIdentity__Azure__UseADTokenForDatabaseConnection
          value: {{ .Values.cloudIdentity.azureSettings.UseADTokenForDatabaseConnection | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Azure" }}
        - name: KeyVault__Provider
          value: "Azure"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        - name: KeyVault__AzureSettings__VaultURI
          value: {{ .Values.cloudIdentity.azureSettings.vaultUri | quote }}
        - name: KeyVault__AzureSettings__AppSettingsVaultURI
          value: {{ .Values.cloudIdentity.azureSettings.appSettingsVaultUri | quote }}
        - name: KeyVault__AzureSettings__ConfigurationReloadIntervalSeconds
          value: {{ .Values.cloudIdentity.secretsManagement.ConfigurationReloadIntervalSeconds | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.global.deployment.platform "google" }}
        {{- if eq .Values.cloudIdentity.googleSettings.credentialsType "serviceAccount" }}
        - name: GOOGLE_APPLICATION_CREDENTIALS 
          value: "{{ .Values.cloudIdentity.googleSettings.ConfigMapFilePath }}/{{ .Values.cloudIdentity.googleSettings.keyName }}"
        {{- end }}
        {{- end }}
        {{- if eq .Values.global.deployment.platform "azure" }}
        {{- if .Values.databases.datawarehouse.bigquery.enabled }}
        - name: GOOGLE_APPLICATION_CREDENTIALS 
          value: "{{ .Values.cloudIdentity.googleSettings.ConfigMapFilePath }}/{{ .Values.cloudIdentity.googleSettings.keyName }}"
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Google" }}
        - name: KeyVault__Provider
          value: "Google"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        {{- if eq .Values.cloudIdentity.amazonSettings.credentialsType "accessKey" }}
        - name: AWS_ACCESS_KEY_ID
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Access_Key_ID
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_SECRET_ACCESS_KEY
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Secret_Access_Key
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_REGION
          value: {{ .Values.cloudIdentity.amazonSettings.region | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        - name: KeyVault__Provider
          value: "Amazon"
        - name: KeyVault__AmazonSettings__AppSettingsTag
          value: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.secretTagKey | quote }}
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        - name: Authentication__EnableRPIAuthentication
          value: {{ .Values.executionservice.enableRPIAuthentication | quote }}
        - name: RealtimeAPIAddressOverride
          value: "http://rpi-realtimeapi:{{ .Values.realtimeapi.service.port }}"
        - name: RPI__SMTP__EmailSenderAddress
          value: {{ .Values.SMTPSettings.SMTP_SenderAddress | quote }}
        - name: RPI__SMTP__Address
          value: {{ .Values.SMTPSettings.SMTP_Address | quote }}
        - name: RPI__SMTP__Port
          value: {{ .Values.SMTPSettings.SMTP_Port | quote }}
        - name: RPI__SMTP__EnableSSL
          value: {{ .Values.SMTPSettings.EnableSSL | quote }}
        - name: RPI__SMTP__UseCredentials
          value: {{ .Values.SMTPSettings.UseCredentials | quote }}
        {{- if .Values.SMTPSettings.UseCredentials }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: RPI__SMTP__Username
          value: {{ .Values.SMTPSettings.SMTP_Username | quote }}
        - name: RPI__SMTP__Password
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: SMTP_Password
        {{- end }}
        {{- end }}
        - name: RPIClient__ApplicationSupportURL
          value: "https://support.redpointglobal.com"
        {{- if .Values.storage.persistentVolumeClaims.FileOutputDirectory.enabled }}
        - name: RPI__FileOutput__Directory
          value: {{  .Values.storage.persistentVolumeClaims.FileOutputDirectory.mountPath }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "sqlserver" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }} 
        {{- end }}  
        {{- if eq .Values.databases.operational.provider "sqlserveronvm" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "postgresql" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: RPI_OperationalDatabaseType
          value: "PostgreSQL"
        {{- end }}
        {{- end }}
        {{- if .Values.redpointAI.enabled }}
        - name: RPI__NLP__ApiBase
          value: {{ .Values.redpointAI.naturalLanguage.ApiBase | quote }} 
        - name: RPI__NLP__ApiVersion
          value: {{ .Values.redpointAI.naturalLanguage.ApiVersion | quote }}
        - name: RPI__NLP__ChatGptEngine
          value: {{ .Values.redpointAI.naturalLanguage.ChatGptEngine | quote }} 
        - name: RPI__NLP__ChatGptTemp
          value: {{ .Values.redpointAI.naturalLanguage.ChatGptTemp | quote }}
        - name: RPI__NLP__SearchEndpoint
          value: {{ .Values.redpointAI.cognitiveSearch.SearchEndpoint | quote }} 
        - name: RPI__NLP__Model__VectorSearchProfile
          value: {{ .Values.redpointAI.cognitiveSearch.VectorSearchProfile | quote }}
        - name: RPI__NLP__Model__VectorSearchConfig
          value: {{ .Values.redpointAI.cognitiveSearch.VectorSearchConfig | quote }}
        - name: RPI__NLP__EmbeddingsModel
          value: {{ .Values.redpointAI.modelStorage.EmbeddingsModel | quote }}
        - name: RPI__NLP__Model__ModelDimensions
          value: {{ .Values.redpointAI.modelStorage.ModelDimensions | quote }}
        - name: RPI__NLP__Model__ContainerName
          value: {{ .Values.redpointAI.modelStorage.ContainerName | quote }}
        - name: RPI__NLP__Model__BlobFolder
          value: {{ .Values.redpointAI.modelStorage.BlobFolder | quote }}
        {{- end }}
        {{- if .Values.redpointAI.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: RPI__NLP__ApiKey
          valueFrom:
            secretKeyRef:
              key:  RPI_NLP_API_KEY
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: RPI__NLP__SearchKey
          valueFrom:
            secretKeyRef:
              key:  RPI_NLP_SEARCH_KEY
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: RPI__NLP__Model__ConnectionString
          valueFrom:
            secretKeyRef:
              key:  RPI_NLP_MODEL_CONNECTION_STRING
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        - name: SeedService__MemoryCacheSize
          value: {{ .Values.executionservice.seedService.memoryCacheSize | quote }}
        - name: SeedService__MaxNumberRetries
          value: {{ .Values.executionservice.seedService.maxNumberRetries | quote }}
        - name: SeedService__MaxRetryDelay
          value: {{ .Values.executionservice.seedService.maxRetryDelay | quote }}
        image: {{ .Values.global.deployment.images.executionservice }}:{{ .Values.global.deployment.images.tag }}
        imagePullPolicy: {{  .Values.global.deployment.images.imagePullPolicy }}
        name: rpi-executionservice
        {{- if .Values.executionservice.probes.enabled }}
        livenessProbe:
          httpGet:
            path: /health/live
            port: 8080
            scheme: HTTP
          initialDelaySeconds: {{ .Values.executionservice.livenessProbe.initialDelaySeconds }}
          periodSeconds: {{ .Values.executionservice.livenessProbe.periodSeconds }}
          timeoutSeconds: {{ .Values.executionservice.livenessProbe.timeoutSeconds }}
          failureThreshold: {{ .Values.executionservice.livenessProbe.failureThreshold }}
        readinessProbe:
          httpGet:
            path: /health/live
            port: 8080
          initialDelaySeconds: {{ .Values.executionservice.readinessProbe.initialDelaySeconds }}
          periodSeconds: {{ .Values.executionservice.readinessProbe.periodSeconds }}
          failureThreshold: {{ .Values.executionservice.readinessProbe.failureThreshold }}
          timeoutSeconds: {{ .Values.executionservice.readinessProbe.timeoutSeconds }}
        startupProbe:
          httpGet:
            path: /health/live
            port: 8080
          failureThreshold: {{ .Values.executionservice.startupProbe.failureThreshold }}
          periodSeconds: {{ .Values.executionservice.startupProbe.periodSeconds }}
          initialDelaySeconds: {{ .Values.executionservice.startupProbe.initialDelaySeconds }}
          timeoutSeconds: {{ .Values.executionservice.startupProbe.timeoutSeconds }}
        {{- end }}
        lifecycle:
          {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
          postStart:
            exec:
              command:
                - /bin/sh
                - -c 
                - cat /app/odbc-config/odbc2.ini > /odbc-config/odbc.ini
          {{- end }}
          preStop:
            exec:
              command:
                - /bin/sh
                - -c
                - |
                  echo "[PreStop] Putting the Execution Service to Sleep...." 
                  curl -s http://localhost:8080/api/operations/sleep
                  while true; do
                    count=$(curl -s http://localhost:8080/metrics | grep '^execution_total_executing_count' | awk '{print $2}')
                    if [ "$count" = "" ]; then
                      echo "[preStop] Metric not found, assuming 0"
                      break
                    fi
                    if [ "$count" = "0" ]; then
                      echo "[preStop] No executing tasks. Proceeding with shutdown."
                      break
                    fi
                    echo "[preStop] Still executing ($count tasks). Sleeping..."
                    sleep 5
                  done
        ports:
        - containerPort: 8080
          name: web-port
          protocol: TCP
        {{- if .Values.securityContext.enabled }}
        securityContext:
          privileged: {{ .Values.securityContext.privileged }}
          allowPrivilegeEscalation: {{ .Values.securityContext.allowPrivilegeEscalation }}
          readOnlyRootFilesystem: {{ .Values.securityContext.readOnlyRootFilesystem }}
          capabilities:
            drop:
            {{- range .Values.securityContext.capabilities.drop }}
              - {{ . }}
            {{- end }}
        {{- end }}
        {{- if .Values.executionservice.resources.enabled }}
        resources:
          {{- if and .Values.executionservice.resources.limits (ne .Values.executionservice.resources.limits.enabled false) }}
          limits:
            {{- with .Values.executionservice.resources.limits.cpu }}
            cpu: {{ . }}
            {{- end }}
            {{- with .Values.executionservice.resources.limits.memory }}
            memory: {{ . }}
            {{- end }}
          {{- end }}
          {{- if and .Values.executionservice.resources.requests (ne .Values.executionservice.resources.requests.enabled false) }}
          requests:
            {{- with .Values.executionservice.resources.requests.cpu }}
            cpu: {{ . }}
            {{- end }}
            {{- with .Values.executionservice.resources.requests.memory }}
            memory: {{ . }}
            {{- end }}
        {{- end }}
        {{- end }}
        volumeMounts:
          {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
          - name: odbc-config
            mountPath: /app/odbc-config/odbc2.ini
            subPath: odbc2.ini
          {{- end }}
          - name: odbcini
            mountPath: /odbc-config
          - name: tempstore
            mountPath: /tmp
          {{- if .Values.databases.datawarehouse.bigquery.enabled }}
          {{- range .Values.databases.datawarehouse.bigquery.connections }}
          {{- if eq .credentialsType "serviceAccount" }}
          - name: {{ .configMapName | quote }}
            mountPath: {{ .ConfigMapFilePath }}/{{ .keyName }}
            subPath: {{ .keyName }}
            readOnly: true
          {{- end }}
          {{- end }}
          {{- end }}
          {{- if .Values.databases.datawarehouse.snowflake.enabled }}
          {{- if eq .Values.databases.datawarehouse.snowflake.credentialsType "snowflake_jwt" }}
          - name: {{ .Values.databases.datawarehouse.snowflake.ConfigMapName }}
            mountPath: "{{ .Values.databases.datawarehouse.snowflake.ConfigMapFilePath }}/{{ .Values.databases.datawarehouse.snowflake.keyName }}"
            subPath: {{ .Values.databases.datawarehouse.snowflake.keyName }}
          {{- end }}
          {{- end }}
          {{- if .Values.storage.persistentVolumeClaims.FileOutputDirectory.enabled }}    
          - name: fileoutputdirectory
            mountPath: {{  .Values.storage.persistentVolumeClaims.FileOutputDirectory.mountPath }}
          {{- end }}
          {{- if .Values.storage.persistentVolumeClaims.Plugins.enabled }}  
          - name: realtimeplugins
            mountPath: {{ .Values.storage.persistentVolumeClaims.Plugins.mountPath }}
          {{- end }}
          {{- if .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.enabled }} 
          - name: rpdmuploaddirectory
            mountPath: {{ .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.mountPath }}
          {{- end }}
      volumes:
        {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
        - name: odbc-config
          configMap:
            name: odbc-config
            defaultMode: 0777
        {{- end }}
        - name: odbcini
          emptyDir: {}
        - name: tempstore
          emptyDir: {}
        {{- if .Values.databases.datawarehouse.bigquery.enabled }}
        {{- range .Values.databases.datawarehouse.bigquery.connections }}
        {{- if eq .credentialsType "serviceAccount" }}
        - name: {{ .configMapName | quote }}
          configMap:
            name: {{ .configMapName | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.databases.datawarehouse.snowflake.enabled }}
        {{- if eq .Values.databases.datawarehouse.snowflake.credentialsType "snowflake_jwt" }}
        - name: {{ .Values.databases.datawarehouse.snowflake.ConfigMapName }}
          configMap:
            name: {{ .Values.databases.datawarehouse.snowflake.ConfigMapName }}
        {{- end }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.FileOutputDirectory.enabled }}
        - name: fileoutputdirectory
          persistentVolumeClaim:
            claimName: {{ .Values.storage.persistentVolumeClaims.FileOutputDirectory.claimName }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.Plugins.enabled }}
        - name: realtimeplugins
          persistentVolumeClaim:
            claimName: {{ .Values.storage.persistentVolumeClaims.Plugins.claimName }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.enabled }}
        - name: rpdmuploaddirectory
          persistentVolumeClaim:
            claimName: {{ .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.claimName }}
        {{- end }}
      {{- if .Values.nodeSelector.enabled }}
      nodeSelector:
        {{ .Values.nodeSelector.key }}: {{ .Values.nodeSelector.value }}
      {{- end }}
      {{- if .Values.tolerations.enabled }}
      tolerations:
        - effect: NoSchedule
          key: {{ .Values.nodeSelector.key }}
          operator: Equal
          value: {{ .Values.nodeSelector.value }}
      {{- end }}
{{- end }}

deploy-integrationapi.yaml.content:
{{- if .Values.integrationapi.serviceAccount.enabled }}
apiVersion: v1
kind: ServiceAccount
metadata:
  name: rpi-integrationapi
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-integrationapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
  {{- if eq .Values.global.deployment.platform "azure" }}
  {{- if .Values.cloudIdentity.enabled }}
  {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
  annotations:
    azure.workload.identity/client-id: {{ .Values.cloudIdentity.azureSettings.managedIdentityClientId }}
  {{- end }}
  {{- end }}
  {{- end }}
  {{- if eq .Values.global.deployment.platform "google" }}
  {{- if .Values.cloudIdentity.enabled }}
  {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
  annotations:
    iam.gke.io/gcp-service-account: {{ .Values.cloudIdentity.googleSettings.serviceAccountEmail | quote }}
  {{- end }}
  {{- end }}
  {{- end }}
{{- end }}

---
{{- if .Values.integrationapi.podDisruptionBudget.enabled }}
apiVersion: policy/v1
kind: PodDisruptionBudget
metadata:
  name: rpi-integrationapi
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-integrationapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  maxUnavailable: {{ .Values.integrationapi.podDisruptionBudget.maxUnavailable }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-integrationapi
{{- end }}


---
{{- if .Values.integrationapi.enabled }}
{{- if eq .Values.integrationapi.type "rollout" }}
apiVersion: v1
kind: Service
metadata:
  name: rpi-integrationapi-preview
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-integrationapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  ports:
  - name: http
    port: {{ .Values.integrationapi.service.port }}
    protocol: TCP
    targetPort: 8080
  selector:
    app.kubernetes.io/name: rpi-integrationapi
{{- end }}
{{- end }}

---
{{- if .Values.integrationapi.enabled }}
apiVersion: v1
kind: Service
metadata:
  name: rpi-integrationapi
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-integrationapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  ports:
  - name: http
    port: {{ .Values.integrationapi.service.port }}
    protocol: TCP
    targetPort: 8080
  selector:
    app.kubernetes.io/name: rpi-integrationapi

---
{{- if eq .Values.integrationapi.type "rollout" }}
apiVersion: argoproj.io/v1alpha1
kind: Rollout
{{- end }}
{{- if eq .Values.integrationapi.type "deployment" }}
apiVersion: apps/v1
kind: Deployment
{{- end }}
metadata:
  name: rpi-integrationapi
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-integrationapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
    {{- with .Values.integrationapi.customLabels }}
    {{- toYaml . | nindent 4 }} 
    {{- end }}
spec:
  {{- if not .Values.integrationapi.autoscaling.enabled }}
  replicas: {{ .Values.integrationapi.replicas }}
  {{- end }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-integrationapi
  {{- if eq .Values.integrationapi.type "rollout" }}
  strategy:
    blueGreen:
      activeService: rpi-integrationapi
      previewService: rpi-integrationapi-preview
      autoPromotionEnabled: {{ .Values.integrationapi.rollout.autoPromotionEnabled }}
  revisionHistoryLimit: {{ .Values.integrationapi.rollout.revisionHistoryLimit }}
  {{- end }}
  template:
    metadata:
      labels:
        app.kubernetes.io/name: rpi-integrationapi
        app.kubernetes.io/instance: {{ .Release.Name }}
        app.kubernetes.io/part-of: rpi
        app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
        {{- with .Values.integrationapi.customLabels }}
        {{- toYaml . | nindent 8 }} 
        {{- end }}
        {{- if eq .Values.global.deployment.platform "azure" }}
        {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
        azure.workload.identity/use: "true"
        {{- end }}
        {{- end }}
      annotations:
        {{- with .Values.integrationapi.customAnnotations }}
        {{- toYaml . | nindent 8 }}
        {{- end }}
        {{- if .Values.integrationapi.customMetrics.enabled }}
        prometheus.io/scrape: {{ .Values.integrationapi.customMetrics.prometheus_scrape | quote }}
        prometheus.io/port: "8080"
        prometheus.io/path: "/metrics"
        {{- end }}
    spec:
      {{- if .Values.global.deployment.images.imagePullSecret.enabled }}
      imagePullSecrets:
      - name: {{ .Values.global.deployment.images.imagePullSecret.name }}
      {{- end }}
      terminationGracePeriodSeconds: {{ .Values.integrationapi.terminationGracePeriodSeconds }}
      serviceAccountName: rpi-integrationapi
      {{- if .Values.securityContext.enabled }}
      securityContext:
        runAsUser: {{ .Values.securityContext.runAsUser }}
        runAsGroup: {{ .Values.securityContext.runAsGroup }}
        fsGroup: {{ .Values.securityContext.fsGroup }}
        runAsNonRoot: {{ .Values.securityContext.runAsNonRoot }}
        supplementalGroups:
          {{- with .Values.securityContext.supplementalGroups }}
          {{- toYaml . | nindent 10 }}
          {{- end }}
      {{- end }}
      affinity:
        podAntiAffinity:
          preferredDuringSchedulingIgnoredDuringExecution:
            - weight: 100
              podAffinityTerm:
                labelSelector:
                  matchLabels:
                    app.kubernetes.io/name: rpi-integrationapi
                topologyKey: kubernetes.io/hostname
      {{- if .Values.topologySpreadConstraints.enabled }}
      topologySpreadConstraints:
        - maxSkew: {{ .Values.topologySpreadConstraints.maxSkew }}
          topologyKey: {{ .Values.topologySpreadConstraints.topologyKey }}
          whenUnsatisfiable: {{ .Values.topologySpreadConstraints.whenUnsatisfiable }}
          labelSelector:
            matchLabels:
              app.kubernetes.io/name: rpi-integrationapi
      {{- end }}
      containers:
      - env:
        - name: Logging__LogLevel__Default
          value: {{ .Values.integrationapi.logging.default | quote }}
        - name: Logging__Database__LogLevel__Default
          value: {{ .Values.integrationapi.logging.database | quote }}
        - name: Logging__Database__RPITrace
          value: {{ .Values.integrationapi.logging.rpiTrace | quote }}
        - name: Logging__Database__RPIError
          value: {{ .Values.integrationapi.logging.rpiError | quote }}
        - name: Logging__Console__LogLevel__Default
          value: {{ .Values.integrationapi.logging.Console | quote }}
        - name: Authentication__EnableRPIAuthentication
          value: {{ .Values.integrationapi.enableRPIAuthentication | quote }}
        - name: RPI__DateTimeSource
          value: {{ .Values.databases.operational.dateTimeSource | quote }}
        - name: ODBCINI
          value: "/odbc-config/odbc.ini"
        {{- if .Values.diagnosticsMode.copytoAzureBlob.enabled }}
        - name: RPI__Diagnostics__CopyToAzure__IsEnabled
          value: "true"
        - name: RPI__Diagnostics__CopyToAzure__StorageAccount
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.accountName | quote }}
        - name: RPI__Diagnostics__CopyToAzure__AccessKey
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: CopyToAzureBlobAccessKey
        - name: RPI__Diagnostics__CopyToAzure__ContainerName
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.containerName | quote }}
        - name: RPI__Diagnostics__CopyToAzure__BlobServiceEndpoint
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.blobServiceEndpoint | quote }}
        - name: RPI__Diagnostics__CopyToAzure__EnableCdn
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.enableCdn | quote }}
        - name: RPI__Diagnostics__CopyToAzure__AzureUseDataLakeStorageGen2
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.UseDataLakeStorageGen2 | quote }}
        {{- end }}
        {{- if .Values.diagnosticsMode.copytoSftp.enabled }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPHost
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpHost | quote }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPUsername
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpUsername | quote }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPPassword
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: CopyToSFTPSecureFTPPassword
        - name: RPI__Diagnostics__CopyToSFTP__PortNumberNumber
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpPort | quote }}
        - name: RPI__Diagnostics__UseSFTP
          value: "true"
        - name: RPI__Diagnostics__CopyToSFTP__IsEnabled
          value: "true"
        {{- end }}
        {{- if .Values.diagnosticsMode.dotNetTools.enabled }}
        - name: DOTNET_BUNDLE_EXTRACT_BASE_DIR
          value: {{ .Values.diagnosticsMode.dotNetTools.extractionBaseDir | quote }} 
        - name: RPI__Diagnostics__UseDotNetTools__Path
          value: {{  .Values.diagnosticsMode.dotNetTools.path  | quote }}
        - name: RPI__Diagnostics__UseDotNetTools__UseCounters
          value: {{ .Values.diagnosticsMode.dotNetTools.useCounters | quote }}
        - name: RPI__Diagnostics__UseDotNetTools__CounterProviderList
          value: '["System.Runtime", "Microsoft.Extensions.Diagnostics.ResourceMonitoring"]'
        - name: RPI__Diagnostics__UseDotNetTools__UseGcDump
          value: {{ .Values.diagnosticsMode.dotNetTools.useGcDump | quote }}
        {{- end }}
        - name: Authentication__RPIAuthentication__AuthorizationHost
          value: "https://{{ .Values.ingress.hosts.integration }}.{{ .Values.ingress.domain }}"
        {{- if .Values.integrationapi.authMetaHttpEnabled }}
        - name: Authentication__RPIAuthentication__AuthMetaHttpHost
          value: "http://rpi-integrationapi"
        - name: Authentication__RPIAuthentication__EnableTransportSecurityRequirement
          value: "false"
        {{- end }}
        - name: EnableSwagger
          value: {{ .Values.integrationapi.enableSwagger | quote }}
        {{- if .Values.cloudIdentity.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Azure" }}
        {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
        - name: CloudIdentity__Azure__CredentialType
          value: "AzureIdentity"
        - name: CloudIdentity__Azure__UseADTokenForDatabaseConnection
          value: {{ .Values.cloudIdentity.azureSettings.UseADTokenForDatabaseConnection | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Azure" }}
        - name: KeyVault__Provider
          value: "Azure"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        - name: KeyVault__AzureSettings__VaultURI
          value: {{ .Values.cloudIdentity.azureSettings.vaultUri | quote }}
        - name: KeyVault__AzureSettings__AppSettingsVaultURI
          value: {{ .Values.cloudIdentity.azureSettings.appSettingsVaultUri | quote }}
        - name: KeyVault__AzureSettings__ConfigurationReloadIntervalSeconds
          value: {{ .Values.cloudIdentity.secretsManagement.ConfigurationReloadIntervalSeconds | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.global.deployment.platform "google" }}
        {{- if eq .Values.cloudIdentity.googleSettings.credentialsType "serviceAccount" }}
        - name: GOOGLE_APPLICATION_CREDENTIALS 
          value: "{{ .Values.cloudIdentity.googleSettings.ConfigMapFilePath }}/{{ .Values.cloudIdentity.googleSettings.keyName }}"
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Google" }}
        - name: KeyVault__Provider
          value: "Google"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        {{- if eq .Values.cloudIdentity.amazonSettings.credentialsType "accessKey" }}
        - name: AWS_ACCESS_KEY_ID
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Access_Key_ID
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_SECRET_ACCESS_KEY
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Secret_Access_Key
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_REGION
          value: {{ .Values.cloudIdentity.amazonSettings.region | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        - name: KeyVault__Provider
          value: "Amazon"
        - name: KeyVault__AmazonSettings__AppSettingsTag
          value: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.secretTagKey | quote }}
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.OpenIdProviders.enabled }}
        {{- if eq .Values.OpenIdProviders.name "KeyCloak" }}
        - name: Authentication__OpenIdProviders__0__Name
          value: "KeyCloak"
        - name: Authentication__OpenIdProviders__0__AuthorizationHost
          value: {{ .Values.OpenIdProviders.authorizationHost | quote }}
        - name: Authentication__OpenIdProviders__0__ClientID
          value: {{ .Values.OpenIdProviders.clientID | quote }}
        - name: Authentication__OpenIdProviders__0__Audience
          value: {{ .Values.OpenIdProviders.audience | quote }}
        - name: Authentication__OpenIdProviders__0__RedirectURL
          value: {{ .Values.OpenIdProviders.redirectURL | quote }}
        - name: Authentication__OpenIdProviders__0__EnableRefreshTokens
          value: {{ .Values.OpenIdProviders.enableRefreshTokens | quote }}
        - name: Authentication__OpenIdProviders__0__ValidateIssuer
          value: {{ .Values.OpenIdProviders.validateIssuer | quote }}
        - name: Authentication__OpenIdProviders__0__ValidateAudience
          value: {{ .Values.OpenIdProviders.validateAudience | quote }}
        - name: Authentication__OpenIdProviders__0__LogoutIdTokenParameter
          value: {{ .Values.OpenIdProviders.logoutIdTokenParameter | quote }}
        {{- range $index, $scope := .Values.OpenIdProviders.customScopes }}
        - name: Authentication__OpenIdProviders__0__CustomScopes__{{ $index }}
          value: {{ $scope | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.OpenIdProviders.enabled }}
        {{- if eq .Values.OpenIdProviders.name "Okta" }}
        - name: Authentication__OpenIdProviders__0__Name
          value: "Okta"
        - name: Authentication__OpenIdProviders__0__AuthorizationHost
          value: {{ .Values.OpenIdProviders.authorizationHost | quote }}
        - name: Authentication__OpenIdProviders__0__ClientID
          value: {{ .Values.OpenIdProviders.clientID | quote }}
        - name: Authentication__OpenIdProviders__0__Audience
          value: {{ .Values.OpenIdProviders.audience | quote }}
        - name: Authentication__OpenIdProviders__0__RedirectURL
          value: {{ .Values.OpenIdProviders.redirectURL | quote }}
        - name: Authentication__OpenIdProviders__0__EnableRefreshTokens
          value: {{ .Values.OpenIdProviders.enableRefreshTokens | quote }}
        - name: Authentication__OpenIdProviders__0__ValidateIssuer
          value: {{ .Values.OpenIdProviders.validateIssuer | quote }}
        - name: Authentication__OpenIdProviders__0__ValidateAudience
          value: {{ .Values.OpenIdProviders.validateAudience | quote }}
        - name: Authentication__OpenIdProviders__0__LogoutIdTokenParameter
          value: {{ .Values.OpenIdProviders.logoutIdTokenParameter | quote }}
        {{- range $index, $scope := .Values.OpenIdProviders.customScopes }}
        - name: Authentication__OpenIdProviders__0__CustomScopes__{{ $index }}
          value: {{ $scope | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.MicrosoftEntraID.enabled }}
        - name: Authentication__Microsoft__Enable
          value: "true"
        - name: Authentication__Microsoft__APIApplicationID
          value: {{ .Values.MicrosoftEntraID.interaction_api_id | quote }}
        - name: Authentication__Microsoft__ClientApplicationID
          value: {{ .Values.MicrosoftEntraID.interaction_client_id | quote }}
        - name: Authentication__Microsoft__TenantID
          value: {{ .Values.MicrosoftEntraID.tenant_id | quote }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "sqlserver" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}   
        {{- if eq .Values.databases.operational.provider "sqlserveronvm" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "postgresql" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: RPI_OperationalDatabaseType
          value: "PostgreSQL"
        {{- end }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.FileOutputDirectory.enabled }}
        - name: RPI__FileOutput__Directory
          value: {{  .Values.storage.persistentVolumeClaims.FileOutputDirectory.mountPath }}
        {{- end }}
        {{- if .Values.redpointAI.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: RPI__NLP__ApiKey
          valueFrom:
            secretKeyRef:
              key:  RPI_NLP_API_KEY
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: RPI__NLP__SearchKey
          valueFrom:
            secretKeyRef:
              key:  RPI_NLP_SEARCH_KEY
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: RPI__NLP__Model__ConnectionString
          valueFrom:
            secretKeyRef:
              key:  RPI_NLP_MODEL_CONNECTION_STRING
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.redpointAI.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: RPI__NLP__ApiBase
          value: {{ .Values.redpointAI.naturalLanguage.ApiBase | quote }} 
        - name: RPI__NLP__ApiVersion
          value: {{ .Values.redpointAI.naturalLanguage.ApiVersion | quote }}
        - name: RPI__NLP__ChatGptEngine
          value: {{ .Values.redpointAI.naturalLanguage.ChatGptEngine | quote }} 
        - name: RPI__NLP__ChatGptTemp
          value: {{ .Values.redpointAI.naturalLanguage.ChatGptTemp | quote }}
        - name: RPI__NLP__SearchEndpoint
          value: {{ .Values.redpointAI.cognitiveSearch.SearchEndpoint | quote }} 
        - name: RPI__NLP__Model__VectorSearchProfile
          value: {{ .Values.redpointAI.cognitiveSearch.VectorSearchProfile | quote }}
        - name: RPI__NLP__Model__VectorSearchConfig
          value: {{ .Values.redpointAI.cognitiveSearch.VectorSearchConfig | quote }}
        - name: RPI__NLP__EmbeddingsModel
          value: {{ .Values.redpointAI.modelStorage.EmbeddingsModel | quote }}
        - name: RPI__NLP__Model__ModelDimensions
          value: {{ .Values.redpointAI.modelStorage.ModelDimensions | quote }}
        - name: RPI__NLP__Model__ContainerName
          value: {{ .Values.redpointAI.modelStorage.ContainerName | quote }}
        - name: RPI__NLP__Model__BlobFolder
          value: {{ .Values.redpointAI.modelStorage.BlobFolder | quote }}
        {{- end }}
        {{- end }}
        image: {{ .Values.global.deployment.images.integrationapi }}:{{ .Values.global.deployment.images.tag }}
        imagePullPolicy: {{  .Values.global.deployment.images.imagePullPolicy }}
        name: rpi-integrationapi
        livenessProbe:
          httpGet:
            path: /health/live
            port: 8080
            scheme: HTTP
          initialDelaySeconds: {{ .Values.integrationapi.livenessProbe.initialDelaySeconds }}
          periodSeconds: {{ .Values.integrationapi.livenessProbe.periodSeconds }}
          timeoutSeconds: {{ .Values.integrationapi.livenessProbe.timeoutSeconds }}
          failureThreshold: {{ .Values.integrationapi.livenessProbe.failureThreshold }}
        readinessProbe:
          httpGet:
            path: /health/live
            port: 8080
          initialDelaySeconds: {{ .Values.integrationapi.readinessProbe.initialDelaySeconds }}
          periodSeconds: {{ .Values.integrationapi.readinessProbe.periodSeconds }}
          failureThreshold: {{ .Values.integrationapi.readinessProbe.failureThreshold }}
          timeoutSeconds: {{ .Values.integrationapi.readinessProbe.timeoutSeconds }}
        startupProbe:
          httpGet:
            path: /health/live
            port: 8080
          failureThreshold: {{ .Values.integrationapi.startupProbe.failureThreshold }}
          periodSeconds: {{ .Values.integrationapi.startupProbe.periodSeconds }}
          initialDelaySeconds: {{ .Values.integrationapi.startupProbe.initialDelaySeconds }}
          timeoutSeconds: {{ .Values.integrationapi.startupProbe.timeoutSeconds }}
        {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
        lifecycle:
          postStart:
            exec:
              command:
                - /bin/sh
                - -c 
                - cat /app/odbc-config/odbc2.ini > /odbc-config/odbc.ini
        {{- end }}
        ports:
        - containerPort: 8080
          name: web-port
          protocol: TCP
        {{- if .Values.securityContext.enabled }}
        securityContext:
          privileged: {{ .Values.securityContext.privileged }}
          allowPrivilegeEscalation: {{ .Values.securityContext.allowPrivilegeEscalation }}
          readOnlyRootFilesystem: {{ .Values.securityContext.readOnlyRootFilesystem }}
          capabilities:
            drop:
            {{- range .Values.securityContext.capabilities.drop }}
              - {{ . }}
            {{- end }}
        {{- end }}
        {{- if .Values.integrationapi.resources.enabled }}
        resources:
          {{- if and .Values.integrationapi.resources.limits (ne .Values.integrationapi.resources.limits.enabled false) }}
          limits:
            {{- with .Values.integrationapi.resources.limits.cpu }}
            cpu: {{ . }}
            {{- end }}
            {{- with .Values.integrationapi.resources.limits.memory }}
            memory: {{ . }}
            {{- end }}
          {{- end }}
          {{- if and .Values.integrationapi.resources.requests (ne .Values.integrationapi.resources.requests.enabled false) }}
          requests:
            {{- with .Values.integrationapi.resources.requests.cpu }}
            cpu: {{ . }}
            {{- end }}
            {{- with .Values.integrationapi.resources.requests.memory }}
            memory: {{ . }}
            {{- end }}
        {{- end }}
        {{- end }}
        volumeMounts:
          {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
          - name: odbc-config
            mountPath: /app/odbc-config/odbc2.ini
            subPath: odbc2.ini
          {{- end }}
          - name: odbcini
            mountPath: /odbc-config
          - name: tempstore
            mountPath: /tmp
          {{- if .Values.databases.datawarehouse.bigquery.enabled }}
          {{- range .Values.databases.datawarehouse.bigquery.connections }}
          {{- if eq .credentialsType "serviceAccount" }}
          - name: {{ .configMapName | quote }}
            mountPath: {{ .ConfigMapFilePath }}/{{ .keyName }}
            subPath: {{ .keyName }}
            readOnly: true
          {{- end }}
          {{- end }}
          {{- end }}
          {{- if .Values.databases.datawarehouse.snowflake.enabled }}
          {{- if eq .Values.databases.datawarehouse.snowflake.credentialsType "snowflake_jwt" }}
          - name: {{ .Values.databases.datawarehouse.snowflake.ConfigMapName }}
            mountPath: "{{ .Values.databases.datawarehouse.snowflake.ConfigMapFilePath }}/{{ .Values.databases.datawarehouse.snowflake.keyName }}"
            subPath: {{ .Values.databases.datawarehouse.snowflake.keyName }}
          {{- end }}
          {{- end }}
          {{- if .Values.storage.persistentVolumeClaims.FileOutputDirectory.enabled }}    
          - name: fileoutputdirectory
            mountPath: {{  .Values.storage.persistentVolumeClaims.FileOutputDirectory.mountPath }}
          {{- end }}
          {{- if .Values.storage.persistentVolumeClaims.Plugins.enabled }}  
          - name: realtimeplugins
            mountPath: {{ .Values.storage.persistentVolumeClaims.Plugins.mountPath }}
          {{- end }}
          {{- if .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.enabled }} 
          - name: rpdmuploaddirectory
            mountPath: {{ .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.mountPath }}
          {{- end }}
      volumes:
        {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
        - name: odbc-config
          configMap:
            name: odbc-config
            defaultMode: 0777
        {{- end }}
        - name: odbcini
          emptyDir: {}
        - name: tempstore
          emptyDir: {}
        {{- if .Values.databases.datawarehouse.bigquery.enabled }}
        {{- range .Values.databases.datawarehouse.bigquery.connections }}
        {{- if eq .credentialsType "serviceAccount" }}
        - name: {{ .configMapName | quote }}
          configMap:
            name: {{ .configMapName | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.databases.datawarehouse.snowflake.enabled }}
        {{- if eq .Values.databases.datawarehouse.snowflake.credentialsType "snowflake_jwt" }}
        - name: {{ .Values.databases.datawarehouse.snowflake.ConfigMapName }}
          configMap:
            name: {{ .Values.databases.datawarehouse.snowflake.ConfigMapName }}
        {{- end }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.FileOutputDirectory.enabled }}
        - name: fileoutputdirectory
          persistentVolumeClaim:
            claimName: {{ .Values.storage.persistentVolumeClaims.FileOutputDirectory.claimName }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.Plugins.enabled }}
        - name: realtimeplugins
          persistentVolumeClaim:
            claimName: {{ .Values.storage.persistentVolumeClaims.Plugins.claimName }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.enabled }}
        - name: rpdmuploaddirectory
          persistentVolumeClaim:
            claimName: {{ .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.claimName }}
        {{- end }}
      {{- if .Values.nodeSelector.enabled }}
      nodeSelector:
        {{ .Values.nodeSelector.key }}: {{ .Values.nodeSelector.value }}
      {{- end }}
      {{- if .Values.tolerations.enabled }}
      tolerations:
        - effect: NoSchedule
          key: {{ .Values.nodeSelector.key }}
          operator: Equal
          value: {{ .Values.nodeSelector.value }}
      {{- end }}
{{- end }}

deploy-interactionapi.yaml.content:
{{- if .Values.interactionapi.serviceAccount.enabled }}
apiVersion: v1
kind: ServiceAccount
metadata:
  name: rpi-interactionapi
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-interactionapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
  {{- if eq .Values.global.deployment.platform "azure" }}
  {{- if .Values.cloudIdentity.enabled }}
  {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
  annotations:
    azure.workload.identity/client-id: {{ .Values.cloudIdentity.azureSettings.managedIdentityClientId }}
  {{- end }}
  {{- end }}
  {{- end }}
  {{- if eq .Values.global.deployment.platform "google" }}
  {{- if .Values.cloudIdentity.enabled }}
  {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
  annotations:
    iam.gke.io/gcp-service-account: {{ .Values.cloudIdentity.googleSettings.serviceAccountEmail | quote }}
  {{- end }}
  {{- end }}
  {{- end }}
{{- end }}

---
{{- if .Values.interactionapi.podDisruptionBudget.enabled }}
apiVersion: policy/v1
kind: PodDisruptionBudget
metadata:
  name: rpi-interactionapi
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-interactionapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  maxUnavailable: {{ .Values.interactionapi.podDisruptionBudget.maxUnavailable }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-interactionapi
{{- end }}


---
{{- if .Values.interactionapi.enabled }}
{{- if eq .Values.interactionapi.type "rollout" }}
apiVersion: v1
kind: Service
metadata:
  name: rpi-interactionapi-preview
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-interactionapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  ports:
  - name: http
    port: {{ .Values.interactionapi.service.port }}
    protocol: TCP
    targetPort: 8080
  selector:
    app.kubernetes.io/name: rpi-interactionapi
{{- end }}
{{- end }}

---
{{- if .Values.interactionapi.enabled }}
apiVersion: v1
kind: Service
metadata:
  name: rpi-interactionapi
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-interactionapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  ports:
  - name: http
    port: {{ .Values.interactionapi.service.port }}
    protocol: TCP
    targetPort: 8080
  selector:
    app.kubernetes.io/name: rpi-interactionapi

---
{{- if eq .Values.interactionapi.type "rollout" }}
apiVersion: argoproj.io/v1alpha1
kind: Rollout
{{- end }}
{{- if eq .Values.interactionapi.type "deployment" }}
apiVersion: apps/v1
kind: Deployment
{{- end }}
metadata:
  name: rpi-interactionapi
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-interactionapi
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
    {{- with .Values.interactionapi.customLabels }}
    {{- toYaml . | nindent 4 }} 
    {{- end }}
spec:
  {{- if not .Values.interactionapi.autoscaling.enabled }}
  replicas: {{ .Values.interactionapi.replicas }}
  {{- end }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-interactionapi
  {{- if eq .Values.interactionapi.type "rollout" }}
  strategy:
    blueGreen:
      activeService: rpi-interactionapi
      previewService: rpi-interactionapi-preview
      autoPromotionEnabled: {{ .Values.interactionapi.rollout.autoPromotionEnabled }}
  revisionHistoryLimit: {{ .Values.interactionapi.rollout.revisionHistoryLimit }}
  {{- end }}
  template:
    metadata:
      labels:
        app.kubernetes.io/name: rpi-interactionapi
        app.kubernetes.io/instance: {{ .Release.Name }}
        app.kubernetes.io/part-of: rpi
        app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
        {{- with .Values.interactionapi.customLabels }}
        {{- toYaml . | nindent 8 }} 
        {{- end }}
        {{- if eq .Values.global.deployment.platform "azure" }}
        {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
        azure.workload.identity/use: "true"
        {{- end }}
        {{- end }}
      annotations:
        {{- with .Values.interactionapi.customAnnotations }}
        {{- toYaml . | nindent 8 }}
        {{- end }}
        {{- if .Values.interactionapi.customMetrics.enabled }}
        prometheus.io/scrape: {{ .Values.interactionapi.customMetrics.prometheus_scrape | quote }}
        prometheus.io/port: "8080"
        prometheus.io/path: "/metrics"
        {{- end }}
    spec:
      {{- if .Values.global.deployment.images.imagePullSecret.enabled }}
      imagePullSecrets:
      - name: {{ .Values.global.deployment.images.imagePullSecret.name }}
      {{- end }}
      terminationGracePeriodSeconds: {{ .Values.interactionapi.terminationGracePeriodSeconds }}
      serviceAccountName: rpi-interactionapi
      {{- if .Values.securityContext.enabled }}
      securityContext:
        runAsUser: {{ .Values.securityContext.runAsUser }}
        runAsGroup: {{ .Values.securityContext.runAsGroup }}
        fsGroup: {{ .Values.securityContext.fsGroup }}
        runAsNonRoot: {{ .Values.securityContext.runAsNonRoot }}
        supplementalGroups:
          {{- with .Values.securityContext.supplementalGroups }}
          {{- toYaml . | nindent 10 }}
          {{- end }}
      {{- end }}
      affinity:
        podAntiAffinity:
          preferredDuringSchedulingIgnoredDuringExecution:
            - weight: 100
              podAffinityTerm:
                labelSelector:
                  matchLabels:
                    app.kubernetes.io/name: rpi-interactionapi
                topologyKey: kubernetes.io/hostname
      {{- if .Values.topologySpreadConstraints.enabled }}
      topologySpreadConstraints:
        - maxSkew: {{ .Values.topologySpreadConstraints.maxSkew }}
          topologyKey: {{ .Values.topologySpreadConstraints.topologyKey }}
          whenUnsatisfiable: {{ .Values.topologySpreadConstraints.whenUnsatisfiable }}
          labelSelector:
            matchLabels:
              app.kubernetes.io/name: rpi-interactionapi
      {{- end }}
      containers:
      - env:
        - name: Logging__LogLevel__Default
          value: {{ .Values.interactionapi.logging.default | quote }}
        - name: Logging__Database__LogLevel__Default
          value: {{ .Values.interactionapi.logging.database | quote }}
        - name: Logging__Database__RPITrace
          value: {{ .Values.interactionapi.logging.rpiTrace | quote }}
        - name: Logging__Database__RPIError
          value: {{ .Values.interactionapi.logging.rpiError | quote }}
        - name: Logging__Console__LogLevel__Default
          value: {{ .Values.interactionapi.logging.Console | quote }}
        - name: RPI__DateTimeSource
          value: {{ .Values.databases.operational.dateTimeSource | quote }}
        - name: ODBCINI
          value: "/odbc-config/odbc.ini"
        - name: RPIClient__HelpStartPageURL
          value: https://docs.redpointglobal.com/rpi/
        {{- if .Values.diagnosticsMode.copytoAzureBlob.enabled }}
        - name: RPI__Diagnostics__CopyToAzure__IsEnabled
