          value: "AzureIdentity"
        - name: CloudIdentity__Azure__UseADTokenForDatabaseConnection
          value: {{ .Values.cloudIdentity.azureSettings.UseADTokenForDatabaseConnection | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Azure" }}
        - name: KeyVault__Provider
          value: "Azure"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        - name: KeyVault__AzureSettings__VaultURI
          value: {{ .Values.cloudIdentity.azureSettings.vaultUri | quote }}
        - name: KeyVault__AzureSettings__AppSettingsVaultURI
          value: {{ .Values.cloudIdentity.azureSettings.appSettingsVaultUri | quote }}
        - name: KeyVault__AzureSettings__ConfigurationReloadIntervalSeconds
          value: {{ .Values.cloudIdentity.secretsManagement.ConfigurationReloadIntervalSeconds | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.global.deployment.platform "google" }}
        {{- if eq .Values.cloudIdentity.googleSettings.credentialsType "serviceAccount" }}
        - name: GOOGLE_APPLICATION_CREDENTIALS 
          value: "{{ .Values.cloudIdentity.googleSettings.ConfigMapFilePath }}/{{ .Values.cloudIdentity.googleSettings.keyName }}"
        {{- end }}
        {{- end }}
        {{- if eq .Values.global.deployment.platform "azure" }}
        {{- if .Values.databases.datawarehouse.bigquery.enabled }}
        - name: GOOGLE_APPLICATION_CREDENTIALS 
          value: "{{ .Values.cloudIdentity.googleSettings.ConfigMapFilePath }}/{{ .Values.cloudIdentity.googleSettings.keyName }}"
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Google" }}
        - name: KeyVault__Provider
          value: "Google"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        {{- if eq .Values.cloudIdentity.amazonSettings.credentialsType "accessKey" }}
        - name: AWS_ACCESS_KEY_ID
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Access_Key_ID
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_SECRET_ACCESS_KEY
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Secret_Access_Key
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_REGION
          value: {{ .Values.cloudIdentity.amazonSettings.region | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        - name: KeyVault__Provider
          value: "Amazon"
        - name: KeyVault__AmazonSettings__AppSettingsTag
          value: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.secretTagKey | quote }}
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.OpenIdProviders.enabled }}
        {{- if eq .Values.OpenIdProviders.name "Keycloak" }}
        - name: Authentication__OpenIdProviders__0__Name
          value: "Keycloak"
        - name: Authentication__OpenIdProviders__0__AuthorizationHost
          value: {{ .Values.OpenIdProviders.authorizationHost | quote }}
        - name: Authentication__OpenIdProviders__0__ClientID
          value: {{ .Values.OpenIdProviders.clientID | quote }}
        - name: Authentication__OpenIdProviders__0__Audience
          value: {{ .Values.OpenIdProviders.audience | quote }}
        - name: Authentication__OpenIdProviders__0__RedirectURL
          value: {{ .Values.OpenIdProviders.redirectURL | quote }}
        - name: Authentication__OpenIdProviders__0__EnableRefreshTokens
          value: {{ .Values.OpenIdProviders.enableRefreshTokens | quote }}
        - name: Authentication__OpenIdProviders__0__ValidateIssuer
          value: {{ .Values.OpenIdProviders.validateIssuer | quote }}
        - name: Authentication__OpenIdProviders__0__ValidateAudience
          value: {{ .Values.OpenIdProviders.validateAudience | quote }}
        - name: Authentication__OpenIdProviders__0__SupportsUserManagement
          value: {{ .Values.OpenIdProviders.supportsUserManagement | quote }}
        - name: Authentication__OpenIdProviders__0__LogoutIdTokenParameter
          value: {{ .Values.OpenIdProviders.logoutIdTokenParameter | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.OpenIdProviders.enabled }}
        {{- if eq .Values.OpenIdProviders.name "Okta" }}
        - name: Authentication__OpenIdProviders__0__Name
          value: "Okta"
        - name: Authentication__OpenIdProviders__0__AuthorizationHost
          value: {{ .Values.OpenIdProviders.authorizationHost | quote }}
        - name: Authentication__OpenIdProviders__0__ClientID
          value: {{ .Values.OpenIdProviders.clientID | quote }}
        - name: Authentication__OpenIdProviders__0__Audience
          value: {{ .Values.OpenIdProviders.audience | quote }}
        - name: Authentication__OpenIdProviders__0__RedirectURL
          value: {{ .Values.OpenIdProviders.redirectURL | quote }}
        - name: Authentication__OpenIdProviders__0__EnableRefreshTokens
          value: {{ .Values.OpenIdProviders.enableRefreshTokens | quote }}
        - name: Authentication__OpenIdProviders__0__ValidateIssuer
          value: {{ .Values.OpenIdProviders.validateIssuer | quote }}
        - name: Authentication__OpenIdProviders__0__ValidateAudience
          value: {{ .Values.OpenIdProviders.validateAudience | quote }}
        - name: Authentication__OpenIdProviders__0__SupportsUserManagement
          value: {{ .Values.OpenIdProviders.supportsUserManagement | quote }}
        - name: Authentication__OpenIdProviders__0__LogoutIdTokenParameter
          value: {{ .Values.OpenIdProviders.logoutIdTokenParameter | quote }}
        {{- range $index, $scope := .Values.OpenIdProviders.customScopes }}
        - name: Authentication__OpenIdProviders__0__CustomScopes__{{ $index }}
          value: {{ $scope | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.MicrosoftEntraID.enabled }}
        - name: Authentication__Microsoft__Enable
          value: "true"
        - name: Authentication__Microsoft__APIApplicationID
          value: {{ .Values.MicrosoftEntraID.interaction_api_id | quote }}
        - name: Authentication__Microsoft__ClientApplicationID
          value: {{ .Values.MicrosoftEntraID.interaction_client_id | quote }}
        - name: Authentication__Microsoft__TenantID
          value: {{ .Values.MicrosoftEntraID.tenant_id | quote }}
        {{- end }}
        - name: Authentication__EnableRPIAuthentication
          value: {{ .Values.interactionapi.enableRPIAuthentication | quote }}
        - name: Authentication__RPIAuthentication__AuthorizationHost
          value: "https://{{ .Values.ingress.hosts.client }}.{{ .Values.ingress.domain }}"
        {{- if .Values.interactionapi.authMetaHttpEnabled }}
        - name: Authentication__RPIAuthentication__AuthMetaHttpHost
          value: "http://rpi-interactionapi"
        - name: Authentication__RPIAuthentication__EnableTransportSecurityRequirement
          value: "false"
        {{- end }}
        {{- if .Values.smartActivation.enabled }}
        {{- if eq .Values.OpenIdProviders.name "Keycloak" }}
        {{- if .Values.interactionapi.useExternalUserManagement }}
        - name: RPI__UserManagement__UseExternalUserManagement
          value: "true"
        - name: RPI__UserManagement__Keycloak__Address
          value: "https://{{ .Values.ingress.hosts.webui }}.{{ .Values.ingress.domain }}/auth/"
        - name: RPI__UserManagement__Keycloak__Realm
          value: {{ .Values.keycloak.realm_name | quote }}
        - name: RPI__UserManagement__Keycloak__ClientId
          value: {{ .Values.keycloak.realm_client_id | quote }}
        - name: RPI__UserManagement__Keycloak__ClientSecret
          value: {{ .Values.keycloak.realm_client_secret | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        - name: EnableSwagger
          value: {{ .Values.interactionapi.enableSwagger | quote }}
        - name: RPI__SMTP__EmailSenderAddress
          value: {{ .Values.SMTPSettings.SMTP_SenderAddress | quote }}
        - name: RPI__SMTP__Address
          value: {{ .Values.SMTPSettings.SMTP_Address | quote }}
        - name: RPI__SMTP__Port
          value: {{ .Values.SMTPSettings.SMTP_Port | quote }}
        - name: RPI__SMTP__EnableSSL
          value: {{ .Values.SMTPSettings.EnableSSL | quote }}
        - name: RPI__SMTP__UseCredentials
          value: {{ .Values.SMTPSettings.UseCredentials | quote }}
        {{- if .Values.SMTPSettings.UseCredentials }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: RPI__SMTP__Username
          value: {{ .Values.SMTPSettings.SMTP_Username | quote }}
        - name: RPI__SMTP__Password
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: SMTP_Password
        {{- end }}
        {{- end }}
        - name: RPIClient__AllowSavingLoginDetails
          value: {{ .Values.interactionapi.allowSavingLoginDetails | quote }}
        - name: RPIClient__AlwaysShowClientsAtLogin
          value: {{ .Values.interactionapi.alwaysShowClientsAtLogin | quote }}
        - name: RPIClient__ApplicationSupportURL
          value: "https://support.redpointglobal.com"
        {{- if .Values.storage.persistentVolumeClaims.FileOutputDirectory.enabled }}
        - name: RPI__FileOutput__Directory
          value: {{  .Values.storage.persistentVolumeClaims.FileOutputDirectory.mountPath }} 
        {{- end }}
        {{- if eq .Values.databases.operational.provider "sqlserver" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "sqlserveronvm" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "postgresql" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: RPI_OperationalDatabaseType
          value: "PostgreSQL"
        {{- end }}
        {{- end }}
        {{- if .Values.redpointAI.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: RPI__NLP__ApiKey
          valueFrom:
            secretKeyRef:
              key:  RPI_NLP_API_KEY
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: RPI__NLP__SearchKey
          valueFrom:
            secretKeyRef:
              key:  RPI_NLP_SEARCH_KEY
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: RPI__NLP__Model__ConnectionString
          valueFrom:
            secretKeyRef:
              key:  RPI_NLP_MODEL_CONNECTION_STRING
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.redpointAI.enabled }}
        - name: RPI__NLP__ApiBase
          value: {{ .Values.redpointAI.naturalLanguage.ApiBase | quote }} 
        - name: RPI__NLP__ApiVersion
          value: {{ .Values.redpointAI.naturalLanguage.ApiVersion | quote }}
        - name: RPI__NLP__ChatGptEngine
          value: {{ .Values.redpointAI.naturalLanguage.ChatGptEngine | quote }} 
        - name: RPI__NLP__ChatGptTemp
          value: {{ .Values.redpointAI.naturalLanguage.ChatGptTemp | quote }}
        - name: RPI__NLP__SearchEndpoint
          value: {{ .Values.redpointAI.cognitiveSearch.SearchEndpoint | quote }} 
        - name: RPI__NLP__Model__VectorSearchProfile
          value: {{ .Values.redpointAI.cognitiveSearch.VectorSearchProfile | quote }}
        - name: RPI__NLP__Model__VectorSearchConfig
          value: {{ .Values.redpointAI.cognitiveSearch.VectorSearchConfig | quote }}
        - name: RPI__NLP__EmbeddingsModel
          value: {{ .Values.redpointAI.modelStorage.EmbeddingsModel | quote }}
        - name: RPI__NLP__Model__ModelDimensions
          value: {{ .Values.redpointAI.modelStorage.ModelDimensions | quote }}
        - name: RPI__NLP__Model__ContainerName
          value: {{ .Values.redpointAI.modelStorage.ContainerName | quote }}
        - name: RPI__NLP__Model__BlobFolder
          value: {{ .Values.redpointAI.modelStorage.BlobFolder | quote }}
        {{- end }}
        image: {{ .Values.global.deployment.images.interactionapi }}:{{ .Values.global.deployment.images.tag }}
        imagePullPolicy: {{  .Values.global.deployment.images.imagePullPolicy }}
        name: rpi-interactionapi
        livenessProbe:
          httpGet:
            path: /health/live
            port: 8080
            scheme: HTTP
          initialDelaySeconds: {{ .Values.interactionapi.livenessProbe.initialDelaySeconds }}
          periodSeconds: {{ .Values.interactionapi.livenessProbe.periodSeconds }}
          timeoutSeconds: {{ .Values.interactionapi.livenessProbe.timeoutSeconds }}
          failureThreshold: {{ .Values.interactionapi.livenessProbe.failureThreshold }}
        readinessProbe:
          httpGet:
            path: /health/live
            port: 8080
          initialDelaySeconds: {{ .Values.interactionapi.readinessProbe.initialDelaySeconds }}
          periodSeconds: {{ .Values.interactionapi.readinessProbe.periodSeconds }}
          failureThreshold: {{ .Values.interactionapi.readinessProbe.failureThreshold }}
          timeoutSeconds: {{ .Values.interactionapi.readinessProbe.timeoutSeconds }}
        startupProbe:
          httpGet:
            path: /health/live
            port: 8080
          failureThreshold: {{ .Values.interactionapi.startupProbe.failureThreshold }}
          periodSeconds: {{ .Values.interactionapi.startupProbe.periodSeconds }}
          initialDelaySeconds: {{ .Values.interactionapi.startupProbe.initialDelaySeconds }}
          timeoutSeconds: {{ .Values.interactionapi.startupProbe.timeoutSeconds }}
        {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
        lifecycle:
          postStart:
            exec:
              command:
                - /bin/sh
                - -c 
                - cat /app/odbc-config/odbc2.ini > /odbc-config/odbc.ini
        {{- end }}
        ports:
        - containerPort: 8080
          name: web-port
          protocol: TCP
        {{- if .Values.securityContext.enabled }}
        securityContext:
          privileged: {{ .Values.securityContext.privileged }}
          allowPrivilegeEscalation: {{ .Values.securityContext.allowPrivilegeEscalation }}
          readOnlyRootFilesystem: {{ .Values.securityContext.readOnlyRootFilesystem }}
          capabilities:
            drop:
            {{- range .Values.securityContext.capabilities.drop }}
              - {{ . }}
            {{- end }}
        {{- end }}
        {{- if .Values.interactionapi.resources.enabled }}
        resources:
          {{- if and .Values.interactionapi.resources.limits (ne .Values.interactionapi.resources.limits.enabled false) }}
          limits:
            {{- with .Values.interactionapi.resources.limits.cpu }}
            cpu: {{ . }}
            {{- end }}
            {{- with .Values.interactionapi.resources.limits.memory }}
            memory: {{ . }}
            {{- end }}
          {{- end }}
          {{- if and .Values.interactionapi.resources.requests (ne .Values.interactionapi.resources.requests.enabled false) }}
          requests:
            {{- with .Values.interactionapi.resources.requests.cpu }}
            cpu: {{ . }}
            {{- end }}
            {{- with .Values.interactionapi.resources.requests.memory }}
            memory: {{ . }}
            {{- end }}
        {{- end }}
        {{- end }}
        volumeMounts:
          {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
          - name: odbc-config
            mountPath: /app/odbc-config/odbc2.ini
            subPath: odbc2.ini
          {{- end }}
          - name: odbcini
            mountPath: /odbc-config
          - name: tempstore
            mountPath: /tmp
          {{- if .Values.databases.datawarehouse.bigquery.enabled }}
          {{- range .Values.databases.datawarehouse.bigquery.connections }}
          {{- if eq .credentialsType "serviceAccount" }}
          - name: {{ .configMapName | quote }}
            mountPath: {{ .ConfigMapFilePath }}/{{ .keyName }}
            subPath: {{ .keyName }}
            readOnly: true
          {{- end }}
          {{- end }}
          {{- end }}
          {{- if .Values.databases.datawarehouse.snowflake.enabled }}
          {{- if eq .Values.databases.datawarehouse.snowflake.credentialsType "snowflake_jwt" }}
          - name: {{ .Values.databases.datawarehouse.snowflake.ConfigMapName }}
            mountPath: "{{ .Values.databases.datawarehouse.snowflake.ConfigMapFilePath }}/{{ .Values.databases.datawarehouse.snowflake.keyName }}"
            subPath: {{ .Values.databases.datawarehouse.snowflake.keyName }}
          {{- end }}
          {{- end }}
          {{- if .Values.storage.persistentVolumeClaims.FileOutputDirectory.enabled }}    
          - name: fileoutputdirectory
            mountPath: {{  .Values.storage.persistentVolumeClaims.FileOutputDirectory.mountPath }}
          {{- end }}
          {{- if .Values.storage.persistentVolumeClaims.Plugins.enabled }}  
          - name: realtimeplugins
            mountPath: {{ .Values.storage.persistentVolumeClaims.Plugins.mountPath }}
          {{- end }}
          {{- if .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.enabled }} 
          - name: rpdmuploaddirectory
            mountPath: {{ .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.mountPath }}
          {{- end }}
      volumes:
        {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
        - name: odbc-config
          configMap:
            name: odbc-config
            defaultMode: 0777
        {{- end }}
        - name: odbcini
          emptyDir: {}
        - name: tempstore
          emptyDir: {}
        {{- if .Values.databases.datawarehouse.bigquery.enabled }}
        {{- range .Values.databases.datawarehouse.bigquery.connections }}
        {{- if eq .credentialsType "serviceAccount" }}
        - name: {{ .configMapName | quote }}
          configMap:
            name: {{ .configMapName | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.databases.datawarehouse.snowflake.enabled }}
        {{- if eq .Values.databases.datawarehouse.snowflake.credentialsType "snowflake_jwt" }}
        - name: {{ .Values.databases.datawarehouse.snowflake.ConfigMapName }}
          configMap:
            name: {{ .Values.databases.datawarehouse.snowflake.ConfigMapName }}
        {{- end }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.FileOutputDirectory.enabled }}
        - name: fileoutputdirectory
          persistentVolumeClaim:
            claimName: {{ .Values.storage.persistentVolumeClaims.FileOutputDirectory.claimName }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.Plugins.enabled }}
        - name: realtimeplugins
          persistentVolumeClaim:
            claimName: {{ .Values.storage.persistentVolumeClaims.Plugins.claimName }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.enabled }}
        - name: rpdmuploaddirectory
          persistentVolumeClaim:
            claimName: {{ .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.claimName }}
        {{- end }}
      {{- if .Values.nodeSelector.enabled }}
      nodeSelector:
        {{ .Values.nodeSelector.key }}: {{ .Values.nodeSelector.value }}
      {{- end }}
      {{- if .Values.tolerations.enabled }}
      tolerations:
        - effect: NoSchedule
          key: {{ .Values.nodeSelector.key }}
          operator: Equal
          value: {{ .Values.nodeSelector.value }}
      {{- end }}
{{- end }}

deploy-netutils.yaml.content:
{{- if .Values.diagnosticsMode.netutils.enabled }}
apiVersion: v1
kind: ServiceAccount
metadata:
  name: net-utils
  namespace: {{ .Release.Namespace }}
  labels:
    app: net-utils

---
apiVersion: apps/v1
kind: Deployment
metadata:
  name: net-utils
  namespace: {{ .Release.Namespace }}
  labels:
    app: net-utils
spec:
  replicas: 1
  selector:
    matchLabels:
      app: net-utils
  template:
    metadata:
      labels:
        app: net-utils
    spec:
      {{- if .Values.global.deployment.images.imagePullSecret.enabled }}
      imagePullSecrets:
      - name: {{ .Values.global.deployment.images.imagePullSecret.name }}
      {{- end }}
      serviceAccountName: net-utils
      {{- with .Values.diagnosticsMode.netutils.securityContext }}
      securityContext:
        runAsNonRoot: {{ .runAsNonRoot }}
        runAsUser: {{ .runAsUser }}
        runAsGroup: {{ .runAsGroup }}
      {{- end }}
      containers:
      - name: net-utils
        image: {{ .Values.global.deployment.images.net_utils }}
        imagePullPolicy: {{  .Values.global.deployment.images.imagePullPolicy }}
        volumeMounts:
        - name: tempdata
          mountPath: /tmp
        {{- with .Values.diagnosticsMode.netutils.securityContext }}
        securityContext:
          runAsNonRoot: {{ .runAsNonRoot }}
          runAsUser: {{ .runAsUser }}
          runAsGroup: {{ .runAsGroup }}
          readOnlyRootFilesystem: {{ .readOnlyRootFilesystem }}
          allowPrivilegeEscalation: {{ .allowPrivilegeEscalation }}
          privileged: {{ .privileged }}
          {{- if or .capabilities.add .capabilities.drop }}
          capabilities:
            {{- if .capabilities.drop }}
            drop:
              {{- range .capabilities.drop }}
              - {{ . }}
              {{- end }}
            {{- end }}
            {{- if .capabilities.add }}
            add:
              {{- range .capabilities.add }}
              - {{ . }}
              {{- end }}
            {{- end }}
          {{- end }}
        {{- end }}
        resources:
          requests:
            cpu: 100m
            memory: 128Mi
          limits:
            cpu: 500m
            memory: 256Mi
      volumes:
      - name: tempdata
        emptyDir: {}
      {{- if .Values.nodeSelector.enabled }}
      nodeSelector:
        {{ .Values.nodeSelector.key }}: {{ .Values.nodeSelector.value }}
      {{- end }}
      {{- if .Values.tolerations.enabled }}
      tolerations:
        - effect: NoSchedule
          key: {{ .Values.nodeSelector.key }}
          operator: Equal
          value: {{ .Values.nodeSelector.value }}
      {{- end }}
{{- end }}

deploy-nodemanager.yaml.content:
{{- if .Values.nodemanager.serviceAccount.enabled }}
{{- if .Values.nodemanager.enabled }}
apiVersion: v1
kind: ServiceAccount
metadata:
  name: rpi-nodemanager
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-nodemanager
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
  {{- if eq .Values.global.deployment.platform "azure" }}
  {{- if .Values.cloudIdentity.enabled }}
  {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
  annotations:
    azure.workload.identity/client-id: {{ .Values.cloudIdentity.azureSettings.managedIdentityClientId }}
  {{- end }}
  {{- end }}
  {{- end }}
  {{- if eq .Values.global.deployment.platform "google" }}
  {{- if .Values.cloudIdentity.enabled }}
  {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
  annotations:
    iam.gke.io/gcp-service-account: {{ .Values.cloudIdentity.googleSettings.serviceAccountEmail | quote }}
  {{- end }}
  {{- end }}
  {{- end }}
{{- end }}
{{- end }}

---
{{- if .Values.nodemanager.podDisruptionBudget.enabled }}
apiVersion: policy/v1
kind: PodDisruptionBudget
metadata:
  name: rpi-nodemanager
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  maxUnavailable: {{ .Values.nodemanager.podDisruptionBudget.maxUnavailable }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-nodemanager
{{- end }}


---
{{- if .Values.nodemanager.enabled }}
{{- if eq .Values.nodemanager.type "rollout" }}
apiVersion: v1
kind: Service
metadata:
  name: rpi-nodemanager-preview
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-nodemanager
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  ports:
  - name: http
    port: {{ .Values.nodemanager.service.port }}
    protocol: TCP
    targetPort: 8080
  selector:
    app.kubernetes.io/name: rpi-nodemanager
{{- end }}
{{- end }}

---
{{- if .Values.nodemanager.enabled }}
apiVersion: v1
kind: Service
metadata:
  name: rpi-nodemanager
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-nodemanager
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  ports:
  - name: http
    port: {{ .Values.nodemanager.service.port }}
    protocol: TCP
    targetPort: 8080
  selector:
    app.kubernetes.io/name: rpi-nodemanager

---
{{- if eq .Values.nodemanager.type "rollout" }}
apiVersion: argoproj.io/v1alpha1
kind: Rollout
{{- end }}
{{- if eq .Values.nodemanager.type "deployment" }}
apiVersion: apps/v1
kind: Deployment
{{- end }}
metadata:
  name: rpi-nodemanager
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-nodemanager
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
    {{- with .Values.nodemanager.customLabels }}
    {{- toYaml . | nindent 4 }} 
    {{- end }}
spec:
  {{- if not .Values.nodemanager.autoscaling.enabled }}
  replicas: {{ .Values.nodemanager.replicas }}
  {{- end }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-nodemanager
  {{- if eq .Values.nodemanager.type "rollout" }}
  strategy:
    blueGreen:
      activeService: rpi-nodemanager
      previewService: rpi-nodemanager-preview
      autoPromotionEnabled: {{ .Values.nodemanager.rollout.autoPromotionEnabled }}
  revisionHistoryLimit: {{ .Values.nodemanager.rollout.revisionHistoryLimit }}
  {{- end }}
  template:
    metadata:
      labels:
        app.kubernetes.io/name: rpi-nodemanager
        app.kubernetes.io/instance: {{ .Release.Name }}
        app.kubernetes.io/part-of: rpi
        app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
        {{- with .Values.nodemanager.customLabels }}
        {{- toYaml . | nindent 8 }} 
        {{- end }}
        {{- if eq .Values.global.deployment.platform "azure" }}
        {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
        azure.workload.identity/use: "true"
        {{- end }}
        {{- end }}
      annotations:
        {{- with .Values.nodemanager.customAnnotations }}
        {{- toYaml . | nindent 8 }}
        {{- end }}
        {{- if .Values.nodemanager.customMetrics.enabled }}
        prometheus.io/scrape: {{ .Values.nodemanager.customMetrics.prometheus_scrape | quote }}
        prometheus.io/port: "8080"
        prometheus.io/path: "/metrics"
        {{- end }}
    spec:
      {{- if .Values.global.deployment.images.imagePullSecret.enabled }}
      imagePullSecrets:
      - name: {{ .Values.global.deployment.images.imagePullSecret.name }}
      {{- end }}
      terminationGracePeriodSeconds: {{ .Values.nodemanager.terminationGracePeriodSeconds }}
      serviceAccountName: rpi-nodemanager
      {{- if .Values.securityContext.enabled }}
      securityContext:
        runAsUser: {{ .Values.securityContext.runAsUser }}
        runAsGroup: {{ .Values.securityContext.runAsGroup }}
        fsGroup: {{ .Values.securityContext.fsGroup }}
        runAsNonRoot: {{ .Values.securityContext.runAsNonRoot }}
        supplementalGroups:
          {{- with .Values.securityContext.supplementalGroups }}
          {{- toYaml . | nindent 10 }}
          {{- end }}
      {{- end }}
      affinity:
        podAntiAffinity:
          preferredDuringSchedulingIgnoredDuringExecution:
            - weight: 100
              podAffinityTerm:
                labelSelector:
                  matchLabels:
                    app.kubernetes.io/name: rpi-nodemanager
                topologyKey: kubernetes.io/hostname
      {{- if .Values.topologySpreadConstraints.enabled }}
      topologySpreadConstraints:
        - maxSkew: {{ .Values.topologySpreadConstraints.maxSkew }}
          topologyKey: {{ .Values.topologySpreadConstraints.topologyKey }}
          whenUnsatisfiable: {{ .Values.topologySpreadConstraints.whenUnsatisfiable }}
          labelSelector:
            matchLabels:
              app.kubernetes.io/name: rpi-nodemanager
      {{- end }}
      containers:
      - env:
        - name: Logging__LogLevel__Default
          value: {{ .Values.nodemanager.logging.default | quote }}
        - name: Logging__Database__LogLevel__Default
          value: {{ .Values.nodemanager.logging.database | quote }}
        - name: Logging__Database__RPITrace
          value: {{ .Values.nodemanager.logging.rpiTrace | quote }}
        - name: Logging__Database__RPIError
          value: {{ .Values.nodemanager.logging.rpiError | quote }}
        - name: Logging__Console__LogLevel__Default
          value: {{ .Values.nodemanager.logging.Console | quote }}
        - name: RPI__DateTimeSource
          value: {{ .Values.databases.operational.dateTimeSource | quote }}
        - name: ODBCINI
          value: "/odbc-config/odbc.ini"
        {{- if .Values.diagnosticsMode.copytoAzureBlob.enabled }}
        - name: RPI__Diagnostics__CopyToAzure__IsEnabled
          value: "true"
        - name: RPI__Diagnostics__CopyToAzure__StorageAccount
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.accountName | quote }}
        - name: RPI__Diagnostics__CopyToAzure__AccessKey
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: CopyToAzureBlobAccessKey
        - name: RPI__Diagnostics__CopyToAzure__ContainerName
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.containerName | quote }}
        - name: RPI__Diagnostics__CopyToAzure__BlobServiceEndpoint
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.blobServiceEndpoint | quote }}
        - name: RPI__Diagnostics__CopyToAzure__EnableCdn
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.enableCdn | quote }}
        - name: RPI__Diagnostics__CopyToAzure__AzureUseDataLakeStorageGen2
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.UseDataLakeStorageGen2 | quote }}
        {{- end }}
        {{- if .Values.diagnosticsMode.copytoSftp.enabled }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPHost
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpHost | quote }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPUsername
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpUsername | quote }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPPassword
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: CopyToSFTPSecureFTPPassword
        - name: RPI__Diagnostics__CopyToSFTP__PortNumberNumber
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpPort | quote }}
        - name: RPI__Diagnostics__UseSFTP
          value: "true"
        - name: RPI__Diagnostics__CopyToSFTP__IsEnabled
          value: "true"
        {{- end }}
        {{- if .Values.diagnosticsMode.dotNetTools.enabled }}
        - name: DOTNET_BUNDLE_EXTRACT_BASE_DIR
          value: {{ .Values.diagnosticsMode.dotNetTools.extractionBaseDir | quote }} 
        - name: RPI__Diagnostics__UseDotNetTools__Path
          value: {{  .Values.diagnosticsMode.dotNetTools.path  | quote }}
        - name: RPI__Diagnostics__UseDotNetTools__UseCounters
          value: {{ .Values.diagnosticsMode.dotNetTools.useCounters | quote }}
        - name: RPI__Diagnostics__UseDotNetTools__CounterProviderList
          value: '["System.Runtime", "Microsoft.Extensions.Diagnostics.ResourceMonitoring"]'
        - name: RPI__Diagnostics__UseDotNetTools__UseGcDump
          value: {{ .Values.diagnosticsMode.dotNetTools.useGcDump | quote }}
        {{- end }}
        {{- if .Values.cloudIdentity.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Azure" }}
        {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
        - name: CloudIdentity__Azure__CredentialType
          value: "AzureIdentity"
        - name: CloudIdentity__Azure__UseADTokenForDatabaseConnection
          value: {{ .Values.cloudIdentity.azureSettings.UseADTokenForDatabaseConnection | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Azure" }}
        - name: KeyVault__Provider
          value: "Azure"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        - name: KeyVault__AzureSettings__VaultURI
          value: {{ .Values.cloudIdentity.azureSettings.vaultUri | quote }}
        - name: KeyVault__AzureSettings__AppSettingsVaultURI
          value: {{ .Values.cloudIdentity.azureSettings.appSettingsVaultUri | quote }}
        - name: KeyVault__AzureSettings__ConfigurationReloadIntervalSeconds
          value: {{ .Values.cloudIdentity.secretsManagement.ConfigurationReloadIntervalSeconds | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.global.deployment.platform "google" }}
        {{- if eq .Values.cloudIdentity.googleSettings.credentialsType "serviceAccount" }}
        - name: GOOGLE_APPLICATION_CREDENTIALS 
          value: "{{ .Values.cloudIdentity.googleSettings.ConfigMapFilePath }}/{{ .Values.cloudIdentity.googleSettings.keyName }}"
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Google" }}
        - name: KeyVault__Provider
          value: "Google"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        {{- if eq .Values.cloudIdentity.amazonSettings.credentialsType "accessKey" }}
        - name: AWS_ACCESS_KEY_ID
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Access_Key_ID
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_SECRET_ACCESS_KEY
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Secret_Access_Key
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_REGION
          value: {{ .Values.cloudIdentity.amazonSettings.region | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        - name: KeyVault__Provider
          value: "Amazon"
        - name: KeyVault__AmazonSettings__AppSettingsTag
          value: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.secretTagKey | quote }}
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        - name: RPIClient__applicationSupportURL
          value: "https://support.redpointglobal.com"
        - name: Authentication__EnableRPIAuthentication
          value: {{ .Values.nodemanager.enableRPIAuthentication | quote }}
        - name: DisableHttpRedirect
          value: "true"
        - name: RealtimeAPIAddressOverride
          value: "http://rpi-realtimeapi:{{ .Values.realtimeapi.service.port }}"
        {{- if eq .Values.databases.operational.provider "sqlserver" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}   
        {{- end }}
        {{- if eq .Values.databases.operational.provider "sqlserveronvm" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "postgresql" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: RPI_OperationalDatabaseType
          value: "PostgreSQL"
        {{- end }}
        {{- end }} 
        {{- if .Values.redpointAI.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: RPI__NLP__ApiKey
          valueFrom:
            secretKeyRef:
              key:  RPI_NLP_API_KEY
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: RPI__NLP__SearchKey
          valueFrom:
            secretKeyRef:
              key:  RPI_NLP_SEARCH_KEY
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: RPI__NLP__Model__ConnectionString
          valueFrom:
            secretKeyRef:
              key:  RPI_NLP_MODEL_CONNECTION_STRING
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.redpointAI.enabled }}
        - name: RPI__NLP__ApiBase
          value: {{ .Values.redpointAI.naturalLanguage.ApiBase | quote }} 
        - name: RPI__NLP__ApiVersion
          value: {{ .Values.redpointAI.naturalLanguage.ApiVersion | quote }}
        - name: RPI__NLP__ChatGptEngine
          value: {{ .Values.redpointAI.naturalLanguage.ChatGptEngine | quote }} 
        - name: RPI__NLP__ChatGptTemp
          value: {{ .Values.redpointAI.naturalLanguage.ChatGptTemp | quote }}
        - name: RPI__NLP__SearchEndpoint
          value: {{ .Values.redpointAI.cognitiveSearch.SearchEndpoint | quote }} 
        - name: RPI__NLP__Model__VectorSearchProfile
          value: {{ .Values.redpointAI.cognitiveSearch.VectorSearchProfile | quote }}
        - name: RPI__NLP__Model__VectorSearchConfig
          value: {{ .Values.redpointAI.cognitiveSearch.VectorSearchConfig | quote }}
        - name: RPI__NLP__EmbeddingsModel
          value: {{ .Values.redpointAI.modelStorage.EmbeddingsModel | quote }}
        - name: RPI__NLP__Model__ModelDimensions
          value: {{ .Values.redpointAI.modelStorage.ModelDimensions | quote }}
        - name: RPI__NLP__Model__ContainerName
          value: {{ .Values.redpointAI.modelStorage.ContainerName | quote }}
        - name: RPI__NLP__Model__BlobFolder
          value: {{ .Values.redpointAI.modelStorage.BlobFolder | quote }}
        {{- end }}
        image: {{ .Values.global.deployment.images.nodemanager }}:{{ .Values.global.deployment.images.tag }}
        imagePullPolicy: {{  .Values.global.deployment.images.imagePullPolicy }}
        name: rpi-nodemanager
        livenessProbe:
          httpGet:
            path: /health/live
            port: 8080
            scheme: HTTP
          initialDelaySeconds: {{ .Values.nodemanager.livenessProbe.initialDelaySeconds }}
          periodSeconds: {{ .Values.nodemanager.livenessProbe.periodSeconds }}
          timeoutSeconds: {{ .Values.nodemanager.livenessProbe.timeoutSeconds }}
          failureThreshold: {{ .Values.nodemanager.livenessProbe.failureThreshold }}
        readinessProbe:
          httpGet:
            path: /health/live
            port: 8080
          initialDelaySeconds: {{ .Values.nodemanager.readinessProbe.initialDelaySeconds }}
          periodSeconds: {{ .Values.nodemanager.readinessProbe.periodSeconds }}
          failureThreshold: {{ .Values.nodemanager.readinessProbe.failureThreshold }}
          timeoutSeconds: {{ .Values.nodemanager.readinessProbe.timeoutSeconds }}
        startupProbe:
          httpGet:
            path: /health/live
            port: 8080
          failureThreshold: {{ .Values.nodemanager.startupProbe.failureThreshold }}
          periodSeconds: {{ .Values.nodemanager.startupProbe.periodSeconds }}
          initialDelaySeconds: {{ .Values.nodemanager.startupProbe.initialDelaySeconds }}
          timeoutSeconds: {{ .Values.nodemanager.startupProbe.timeoutSeconds }}
        {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
        lifecycle:
          postStart:
            exec:
              command:
                - /bin/sh
                - -c 
                - cat /app/odbc-config/odbc2.ini > /odbc-config/odbc.ini
        {{- end }}
        ports:
        - containerPort: 8080
          name: web-port
          protocol: TCP
        {{- if .Values.securityContext.enabled }}
        securityContext:
          privileged: {{ .Values.securityContext.privileged }}
          allowPrivilegeEscalation: {{ .Values.securityContext.allowPrivilegeEscalation }}
          readOnlyRootFilesystem: {{ .Values.securityContext.readOnlyRootFilesystem }}
          capabilities:
            drop:
            {{- range .Values.securityContext.capabilities.drop }}
              - {{ . }}
            {{- end }}
        {{- end }}
        {{- if .Values.nodemanager.resources.enabled }}
        resources:
          {{- if and .Values.nodemanager.resources.limits (ne .Values.nodemanager.resources.limits.enabled false) }}
          limits:
            {{- with .Values.nodemanager.resources.limits.cpu }}
            cpu: {{ . }}
            {{- end }}
            {{- with .Values.nodemanager.resources.limits.memory }}
            memory: {{ . }}
            {{- end }}
          {{- end }}
          {{- if and .Values.nodemanager.resources.requests (ne .Values.nodemanager.resources.requests.enabled false) }}
          requests:
            {{- with .Values.nodemanager.resources.requests.cpu }}
            cpu: {{ . }}
            {{- end }}
            {{- with .Values.nodemanager.resources.requests.memory }}
            memory: {{ . }}
            {{- end }}
        {{- end }}
        {{- end }}
        volumeMounts:
          {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
          - name: odbc-config
            mountPath: /app/odbc-config/odbc2.ini
            subPath: odbc2.ini
          {{- end }}
          - name: odbcini
            mountPath: /odbc-config
          - name: tempstore
            mountPath: /tmp
          {{- if .Values.databases.datawarehouse.bigquery.enabled }}
          {{- range .Values.databases.datawarehouse.bigquery.connections }}
          {{- if eq .credentialsType "serviceAccount" }}
          - name: {{ .configMapName | quote }}
            mountPath: {{ .ConfigMapFilePath }}/{{ .keyName }}
            subPath: {{ .keyName }}
            readOnly: true
          {{- end }}
          {{- end }}
          {{- end }}
          {{- if .Values.databases.datawarehouse.snowflake.enabled }}
          {{- if eq .Values.databases.datawarehouse.snowflake.credentialsType "snowflake_jwt" }}
          - name: {{ .Values.databases.datawarehouse.snowflake.ConfigMapName }}
            mountPath: "{{ .Values.databases.datawarehouse.snowflake.ConfigMapFilePath }}/{{ .Values.databases.datawarehouse.snowflake.keyName }}"
            subPath: {{ .Values.databases.datawarehouse.snowflake.keyName }}
          {{- end }}
          {{- end }}
          {{- if .Values.storage.persistentVolumeClaims.FileOutputDirectory.enabled }}    
          - name: fileoutputdirectory
            mountPath: {{  .Values.storage.persistentVolumeClaims.FileOutputDirectory.mountPath }}
          {{- end }}
          {{- if .Values.storage.persistentVolumeClaims.Plugins.enabled }}  
          - name: realtimeplugins
            mountPath: {{ .Values.storage.persistentVolumeClaims.Plugins.mountPath }}
          {{- end }}
          {{- if .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.enabled }} 
          - name: rpdmuploaddirectory
            mountPath: {{ .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.mountPath }}
          {{- end }}
      volumes:
        {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
        - name: odbc-config
          configMap:
            name: odbc-config
            defaultMode: 0777
        {{- end }}
        - name: odbcini
          emptyDir: {}
        - name: tempstore
          emptyDir: {}
        {{- if .Values.databases.datawarehouse.bigquery.enabled }}
        {{- range .Values.databases.datawarehouse.bigquery.connections }}
        {{- if eq .credentialsType "serviceAccount" }}
        - name: {{ .configMapName | quote }}
          configMap:
            name: {{ .configMapName | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.databases.datawarehouse.snowflake.enabled }}
        {{- if eq .Values.databases.datawarehouse.snowflake.credentialsType "snowflake_jwt" }}
        - name: {{ .Values.databases.datawarehouse.snowflake.ConfigMapName }}
          configMap:
            name: {{ .Values.databases.datawarehouse.snowflake.ConfigMapName }}
        {{- end }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.FileOutputDirectory.enabled }}
        - name: fileoutputdirectory
          persistentVolumeClaim:
            claimName: {{ .Values.storage.persistentVolumeClaims.FileOutputDirectory.claimName }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.Plugins.enabled }}
        - name: realtimeplugins
          persistentVolumeClaim:
            claimName: {{ .Values.storage.persistentVolumeClaims.Plugins.claimName }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.enabled }}
        - name: rpdmuploaddirectory
          persistentVolumeClaim:
            claimName: {{ .Values.storage.persistentVolumeClaims.DataManagementUploadDirectory.claimName }}
        {{- end }}
      {{- if .Values.nodeSelector.enabled }}
      nodeSelector:
        {{ .Values.nodeSelector.key }}: {{ .Values.nodeSelector.value }}
      {{- end }}
      {{- if .Values.tolerations.enabled }}
      tolerations:
        - effect: NoSchedule
          key: {{ .Values.nodeSelector.key }}
          operator: Equal
          value: {{ .Values.nodeSelector.value }}
      {{- end }}
{{- end }}

deploy-queuereader.yaml.content:
{{- if .Values.queuereader.serviceAccount.enabled }}
apiVersion: v1
kind: ServiceAccount
metadata:
  name: rpi-queuereader
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-queuereader
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
  {{- if eq .Values.global.deployment.platform "azure" }}
  {{- if .Values.cloudIdentity.enabled }}
  {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
  annotations:
    azure.workload.identity/client-id: {{ .Values.cloudIdentity.azureSettings.managedIdentityClientId }}
  {{- end }}
  {{- end }}
  {{- end }}
  {{- if eq .Values.global.deployment.platform "google" }}
  {{- if .Values.cloudIdentity.enabled }}
  {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
  annotations:
    iam.gke.io/gcp-service-account: {{ .Values.cloudIdentity.googleSettings.serviceAccountEmail | quote }}
  {{- end }}
  {{- end }}
  {{- end }}
{{- end }}

---
{{- if .Values.queuereader.podDisruptionBudget.enabled }}
apiVersion: policy/v1
kind: PodDisruptionBudget
metadata:
  name: rpi-queuereader
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  maxUnavailable: {{ .Values.queuereader.podDisruptionBudget.maxUnavailable }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-queuereader
{{- end }}


---
{{- if .Values.queuereader.enabled }}
{{- if eq .Values.queuereader.type "rollout" }}
apiVersion: v1
kind: Service
metadata:
  name: rpi-queuereader-preview
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-queuereader
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  ports:
  - name: http
    port: {{ .Values.queuereader.service.port }}
    protocol: TCP
    targetPort: 8080
  selector:
    app.kubernetes.io/name: rpi-queuereader
{{- end }}
{{- end }}

---
{{- if .Values.queuereader.enabled }}
apiVersion: v1
kind: Service
metadata:
  name: rpi-queuereader
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-queuereader
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  ports:
  - name: http
    port: {{ .Values.queuereader.service.port }}
    protocol: TCP
    targetPort: 8080
  selector:
    app.kubernetes.io/name: rpi-queuereader

---
{{- if eq .Values.queuereader.type "rollout" }}
apiVersion: argoproj.io/v1alpha1
kind: Rollout
{{- end }}
{{- if eq .Values.queuereader.type "deployment" }}
apiVersion: apps/v1
kind: Deployment
{{- end }}
metadata:
  name: rpi-queuereader
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-queuereader
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
    {{- with .Values.queuereader.customLabels }}
    {{- toYaml . | nindent 4 }} 
    {{- end }}
spec:
  {{- if not .Values.queuereader.autoscaling.enabled }}
  replicas: {{ .Values.queuereader.replicas }}
  {{- end }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-queuereader
  {{- if eq .Values.queuereader.type "rollout" }}
  strategy:
    blueGreen:
      activeService: rpi-queuereader
      previewService: rpi-queuereader-preview
      autoPromotionEnabled: {{ .Values.queuereader.rollout.autoPromotionEnabled }}
  revisionHistoryLimit: {{ .Values.queuereader.rollout.revisionHistoryLimit }}
  {{- end }}
  template:
    metadata:
      labels:
        app.kubernetes.io/name: rpi-queuereader
        app.kubernetes.io/instance: {{ .Release.Name }}
        app.kubernetes.io/part-of: rpi
        app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
        {{- with .Values.queuereader.customLabels }}
        {{- toYaml . | nindent 8 }} 
        {{- end }}
        {{- if eq .Values.global.deployment.platform "azure" }}
        {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
        azure.workload.identity/use: "true"
        {{- end }}
        {{- end }}
      annotations:
        {{- with .Values.queuereader.customAnnotations }}
        {{- toYaml . | nindent 8 }}
        {{- end }}
        {{- if .Values.queuereader.customMetrics.enabled }}
        prometheus.io/scrape: {{ .Values.queuereader.customMetrics.prometheus_scrape | quote }}
        prometheus.io/port: "8080"
        prometheus.io/path: "/metrics"
        {{- end }}
    spec:
      {{- if .Values.global.deployment.images.imagePullSecret.enabled }}
      imagePullSecrets:
      - name: {{ .Values.global.deployment.images.imagePullSecret.name }}
      {{- end }}
      terminationGracePeriodSeconds: {{ .Values.queuereader.terminationGracePeriodSeconds }}
      serviceAccountName: rpi-queuereader
      {{- if .Values.securityContext.enabled }}
      securityContext:
        runAsUser: {{ .Values.securityContext.runAsUser }}
        runAsGroup: {{ .Values.securityContext.runAsGroup }}
        fsGroup: {{ .Values.securityContext.fsGroup }}
        runAsNonRoot: {{ .Values.securityContext.runAsNonRoot }}
        supplementalGroups:
          {{- with .Values.securityContext.supplementalGroups }}
          {{- toYaml . | nindent 10 }}
          {{- end }}
      {{- end }}
      affinity:
        podAntiAffinity:
          preferredDuringSchedulingIgnoredDuringExecution:
            - weight: 100
              podAffinityTerm:
                labelSelector:
                  matchLabels:
                    app.kubernetes.io/name: rpi-queuereader
                topologyKey: kubernetes.io/hostname
      {{- if .Values.topologySpreadConstraints.enabled }}
      topologySpreadConstraints:
        - maxSkew: {{ .Values.topologySpreadConstraints.maxSkew }}
          topologyKey: {{ .Values.topologySpreadConstraints.topologyKey }}
          whenUnsatisfiable: {{ .Values.topologySpreadConstraints.whenUnsatisfiable }}
          labelSelector:
            matchLabels:
              app.kubernetes.io/name: rpi-queuereader
      {{- end }}
      containers:
      - env:
        {{- if .Values.executionservice.internalCache.enabled }}
        - name: InternalCache__IsEnabled
          value: "true"
        - name: InternalCache__BackupToOpsDBInterval
          value: {{ .Values.executionservice.internalCache.backupToOpsDBInterval | quote }}
        - name: InternalCache__MaxNumberRetries
          value: {{ .Values.executionservice.internalCache.maxNumberRetries | quote }}
        - name: InternalCache__MaxRetryDelay
          value: {{ .Values.executionservice.internalCache.maxRetryDelay | quote }}
        - name: InternalCache__FailOnPrimaryDataLoss
          value: {{ .Values.executionservice.internalCache.failOnPrimaryDataLoss | quote }}
        - name: InternalCache__FailOnCacheConnectionError
          value: {{ .Values.executionservice.internalCache.failOnCacheConnectionError | quote }}
        {{- end }}
        {{- if .Values.executionservice.internalCache.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: InternalCache__RedisSettings__IPAddress
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: ExecutionService_RedisCache_ConnectionString
        {{- end }}
        {{- end }}
        - name: Logging__LogLevel__Default
          value: {{ .Values.queuereader.logging.default | quote }}
        - name: Logging__Database__LogLevel__Default
          value: {{ .Values.queuereader.logging.database | quote }}
        - name: Logging__Database__RPITrace
          value: {{ .Values.queuereader.logging.rpiTrace | quote }}
        - name: Logging__Database__RPIError
          value: {{ .Values.queuereader.logging.rpiError | quote }}
        - name: Logging__Console__LogLevel__Default
          value: {{ .Values.queuereader.logging.Console | quote }}
        - name: RPI__DateTimeSource
          value: {{ .Values.databases.operational.dateTimeSource | quote }}
        - name: ODBCINI
          value: "/odbc-config/odbc.ini"
        {{- if .Values.diagnosticsMode.copytoAzureBlob.enabled }}
        - name: RPI__Diagnostics__CopyToAzure__IsEnabled
          value: "true"
        - name: RPI__Diagnostics__CopyToAzure__StorageAccount
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.accountName | quote }}
        - name: RPI__Diagnostics__CopyToAzure__AccessKey
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: CopyToAzureBlobAccessKey
        - name: RPI__Diagnostics__CopyToAzure__ContainerName
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.containerName | quote }}
        - name: RPI__Diagnostics__CopyToAzure__BlobServiceEndpoint
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.blobServiceEndpoint | quote }}
        - name: RPI__Diagnostics__CopyToAzure__EnableCdn
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.enableCdn | quote }}
        - name: RPI__Diagnostics__CopyToAzure__AzureUseDataLakeStorageGen2
          value: {{ .Values.diagnosticsMode.copytoAzureBlob.UseDataLakeStorageGen2 | quote }}
        {{- end }}
        {{- if .Values.diagnosticsMode.copytoSftp.enabled }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPHost
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpHost | quote }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPUsername
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpUsername | quote }}
        - name: RPI__Diagnostics__CopyToSFTP__SecureFTPPassword
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: CopyToSFTPSecureFTPPassword
        - name: RPI__Diagnostics__CopyToSFTP__PortNumberNumber
          value: {{ .Values.diagnosticsMode.copytoSftp.sftpPort | quote }}
        - name: RPI__Diagnostics__UseSFTP
          value: "true"
        - name: RPI__Diagnostics__CopyToSFTP__IsEnabled
          value: "true"
        {{- end }}
        {{- if .Values.diagnosticsMode.dotNetTools.enabled }}
        - name: DOTNET_BUNDLE_EXTRACT_BASE_DIR
          value: {{ .Values.diagnosticsMode.dotNetTools.extractionBaseDir | quote }} 
        - name: RPI__Diagnostics__UseDotNetTools__Path
          value: {{  .Values.diagnosticsMode.dotNetTools.path  | quote }}
        - name: RPI__Diagnostics__UseDotNetTools__UseCounters
          value: {{ .Values.diagnosticsMode.dotNetTools.useCounters | quote }}
        - name: RPI__Diagnostics__UseDotNetTools__CounterProviderList
          value: '["System.Runtime", "Microsoft.Extensions.Diagnostics.ResourceMonitoring"]'
        - name: RPI__Diagnostics__UseDotNetTools__UseGcDump
          value: {{ .Values.diagnosticsMode.dotNetTools.useGcDump | quote }}
        {{- end }}
        - name: RPI__ServiceHostName
          value: "http://rpi-interactionapi"
        - name: RPI__ServiceHostPortNumber
          value: {{ .Values.interactionapi.service.port | quote }}
        - name: RealtimeAPIAddressOverride
          value: "http://rpi-realtimeapi:{{ .Values.realtimeapi.service.port }}"
        {{- if eq .Values.databases.operational.provider "postgresql" }}
        - name: RPI_OperationalDatabaseType
          value: "PostgreSQL"
        {{- end }}
        {{- if .Values.cloudIdentity.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Azure" }}
        {{- if eq .Values.cloudIdentity.azureSettings.credentialsType "workloadIdentity" }}
        - name: CloudIdentity__Azure__CredentialType
          value: "AzureIdentity"
        - name: CloudIdentity__Azure__UseADTokenForDatabaseConnection
          value: {{ .Values.cloudIdentity.azureSettings.UseADTokenForDatabaseConnection | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Azure" }}
        - name: KeyVault__Provider
          value: "Azure"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        - name: KeyVault__AzureSettings__VaultURI
          value: {{ .Values.cloudIdentity.azureSettings.vaultUri | quote }}
        - name: KeyVault__AzureSettings__AppSettingsVaultURI
          value: {{ .Values.cloudIdentity.azureSettings.appSettingsVaultUri | quote }}
        - name: KeyVault__AzureSettings__ConfigurationReloadIntervalSeconds
          value: {{ .Values.cloudIdentity.secretsManagement.ConfigurationReloadIntervalSeconds | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.global.deployment.platform "google" }}
        {{- if eq .Values.cloudIdentity.googleSettings.credentialsType "serviceAccount" }}
        - name: GOOGLE_APPLICATION_CREDENTIALS 
          value: "{{ .Values.cloudIdentity.googleSettings.ConfigMapFilePath }}/{{ .Values.cloudIdentity.googleSettings.keyName }}"
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.provider "Google" }}
        - name: KeyVault__Provider
          value: "Google"
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        {{- if eq .Values.cloudIdentity.amazonSettings.credentialsType "accessKey" }}
        - name: AWS_ACCESS_KEY_ID
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Access_Key_ID
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_SECRET_ACCESS_KEY
          valueFrom:
            secretKeyRef:
              key: AWS_SM_Secret_Access_Key
              name: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.credentialSecretName | quote }}
        - name: AWS_REGION
          value: {{ .Values.cloudIdentity.amazonSettings.region | quote }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.cloudIdentity.secretsManagement.enabled }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
        - name: KeyVault__Provider
          value: "Amazon"
        - name: KeyVault__AmazonSettings__AppSettingsTag
          value: {{ .Values.cloudIdentity.amazonSettings.secretsManagerSettings.secretTagKey | quote }}
        - name: KeyVault__UseForAppSettings
          value: {{ .Values.cloudIdentity.secretsManagement.UseForAppSettings | quote }}
        - name: KeyVault__UseForConfigPasswords
          value: {{ .Values.cloudIdentity.secretsManagement.UseForConfigPasswords | quote }}
        {{- end }}
        {{- end }}
        {{- if .Values.storage.persistentVolumeClaims.FileOutputDirectory.enabled }}
        - name: RPI__FileOutput__Directory
          value: {{  .Values.storage.persistentVolumeClaims.FileOutputDirectory.mountPath }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "sqlserver" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "sqlserveronvm" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        {{- if eq .Values.databases.operational.provider "postgresql" }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        - name: CONNECTIONSTRINGS__LOGGINGDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Logging_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        - name: CONNECTIONSTRINGS__OPERATIONALDATABASE
          valueFrom:
            secretKeyRef:
              key: ConnectionString_Operations_Database
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
        {{- end }}
        {{- end }}
        - name: QueueService__QueueListener__IsEnabled
          value: {{ .Values.queuereader.queueListenerEnabled | quote }}
        - name: QueueService__RealtimeConfiguration__IsCallbackServiceProcessingEnabled
          value: {{ .Values.queuereader.isCallbackServiceProcessingEnabled | quote }}
        - name: QueueService__QueueListener__QueuePath
          value: {{ .Values.realtimeapi.queueProvider.queueNames.listenerQueuePath | quote }}
        - name: QueueService__QueueListener__ThreadPoolSize
          value: {{ .Values.queuereader.threadPoolSize | quote }}
        - name: QueueService__QueueListener__TimeoutMinutes
          value: {{ .Values.queuereader.timeoutMinutes | quote }}
        - name: QueueService__QueueListener__MaxBatchSize
          value: {{ .Values.queuereader.maxBatchSize | quote }}
        - name: QueueService__QueueListener__UseMessageLocks
          value: {{ .Values.queuereader.useMessageLocks | quote }}
        - name: QueueService__RealtimeConfiguration__IsFormProcessingEnabled
          value: {{ .Values.queuereader.isFormProcessingEnabled | quote }}
        - name: QueueService__RealtimeConfiguration__IsEventProcessingEnabled
          value: {{ .Values.queuereader.isEventProcessingEnabled | quote }}
        - name: QueueService__RealtimeConfiguration__IsCacheProcessingEnabled
          value: {{ .Values.queuereader.isCacheProcessingEnabled | quote }}
        {{- range $index, $scope := .Values.queuereader.realtimeConfiguration.tenantIds }}
        - name: QueueService__RealtimeConfiguration__TenantIDs__{{ $index }}
          value: {{ $scope | quote }}
        {{- end }}
        - name: QueueService__QueueListener__ListenerQueueNonActiveQueuePath
          value: {{ .Values.queuereader.listenerQueueNonActiveQueuePath | quote}}
        - name: QueueService__QueueListener__ListenerQueueNonActiveTTLDays
          value: {{ .Values.queuereader.listenerQueueNonActiveTTLDays | quote}}
        - name: QueueService__QueueListener__ListenerQueueErrorQueuePath
          value: {{ .Values.queuereader.listenerQueueErrorQueuePath | quote}}
        - name: QueueService__QueueListener__ListenerQueueErrorTTLDays
          value: {{ .Values.queuereader.listenerQueueErrorTTLDays | quote}}
        - name: QueueService__RealtimeConfiguration__IsDistributed
          value: {{ .Values.queuereader.realtimeConfiguration.isDistributed | quote }}
        {{- if .Values.queuereader.realtimeConfiguration.isDistributed }}
        {{- if eq .Values.queuereader.realtimeConfiguration.distributedCache.provider "redis" }}
        - name: QueueService__RealtimeConfiguration__DistributedCache__Provider
          value: "Redis"
        {{- end }}
        {{- end }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        {{- if .Values.queuereader.realtimeConfiguration.isDistributed }}
        {{- if eq .Values.queuereader.realtimeConfiguration.distributedCache.provider "redis" }}
        - name: QueueService__RealtimeConfiguration__DistributedCache__RedisSettings__IPAddress
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: QueueService_RedisCache_ConnectionString
        {{- end }}
        {{- end }}
        {{- end }}
        {{- if .Values.queuereader.realtimeConfiguration.isDistributed }}
        {{- if eq .Values.queuereader.realtimeConfiguration.distributedQueue.provider "rabbitmq" }}
        - name: QueueService__RealtimeConfiguration__DistributedQueue__Assembly
          value: "RedPoint.Resonance.RabbitMQAccess"
        - name: QueueService__RealtimeConfiguration__DistributedQueue__Type
          value: "RedPoint.Resonance.RabbitMQAccess.RabbitMQFactory"
        - name: QueueService__RealtimeConfiguration__DistributedQueue__Settings__0__Key
          value: "Hostname"
        - name: QueueService__RealtimeConfiguration__DistributedQueue__Settings__0__Value
          value: {{ .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.hostname | quote }}
        - name: QueueService__RealtimeConfiguration__DistributedQueue__Settings__1__Key
          value: "VirtualHost"
        - name: QueueService__RealtimeConfiguration__DistributedQueue__Settings__1__Value
          value: {{ .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.virtualhost | quote }}
        - name: QueueService__RealtimeConfiguration__DistributedQueue__Settings__2__Key
          value: "UserName"
        - name: QueueService__RealtimeConfiguration__DistributedQueue__Settings__2__Value
          value: {{ .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.username | quote }}
        - name: QueueService__RealtimeConfiguration__DistributedQueue__Settings__3__Key
          value: "Password"
        {{- end }}
        {{- end }}
        {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
        {{- if .Values.queuereader.realtimeConfiguration.isDistributed }}
        {{- if eq .Values.queuereader.realtimeConfiguration.distributedQueue.provider "rabbitmq" }}
        - name: QueueService__RealtimeConfiguration__DistributedQueue__Settings__3__Value
          valueFrom:
            secretKeyRef:
              name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
              key: QueueService_RabbitMQ_Password
        {{- end }}
        {{- end }}
        {{- end }}
        image: {{ .Values.global.deployment.images.queuereader }}:{{ .Values.global.deployment.images.tag }}
        imagePullPolicy: {{  .Values.global.deployment.images.imagePullPolicy }}
        name: rpi-queuereader
        livenessProbe:
          tcpSocket:
            port: 8080
          initialDelaySeconds: {{ .Values.queuereader.livenessProbe.initialDelaySeconds }}
          periodSeconds: {{ .Values.queuereader.livenessProbe.periodSeconds }}
          timeoutSeconds: {{ .Values.queuereader.livenessProbe.timeoutSeconds }}
          failureThreshold: {{ .Values.queuereader.livenessProbe.failureThreshold }}
        readinessProbe:
          httpGet:
            path: /health/live
            port: 8080
          initialDelaySeconds: {{ .Values.queuereader.readinessProbe.initialDelaySeconds }}
          periodSeconds: {{ .Values.queuereader.readinessProbe.periodSeconds }}
          failureThreshold: {{ .Values.queuereader.readinessProbe.failureThreshold }}
          timeoutSeconds: {{ .Values.queuereader.readinessProbe.timeoutSeconds }}
        startupProbe:
          httpGet:
            path: /health/live
            port: 8080
          failureThreshold: {{ .Values.queuereader.startupProbe.failureThreshold }}
          periodSeconds: {{ .Values.queuereader.startupProbe.periodSeconds }}
          initialDelaySeconds: {{ .Values.queuereader.startupProbe.initialDelaySeconds }}
          timeoutSeconds: {{ .Values.queuereader.startupProbe.timeoutSeconds }}
        {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
        lifecycle:
          postStart:
            exec:
              command:
                - /bin/sh
                - -c 
                - cat /app/odbc-config/odbc2.ini > /odbc-config/odbc.ini
        {{- end }}
        ports:
        - containerPort: 8080
          name: web-port
          protocol: TCP
        {{- if .Values.securityContext.enabled }}
        securityContext:
          privileged: {{ .Values.securityContext.privileged }}
          allowPrivilegeEscalation: {{ .Values.securityContext.allowPrivilegeEscalation }}
          readOnlyRootFilesystem: {{ .Values.securityContext.readOnlyRootFilesystem }}
          capabilities:
            drop:
            {{- range .Values.securityContext.capabilities.drop }}
              - {{ . }}
            {{- end }}
        {{- end }}
        {{- if .Values.queuereader.resources.enabled }}
        resources:
          {{- if and .Values.queuereader.resources.limits (ne .Values.queuereader.resources.limits.enabled false) }}
          limits:
            {{- with .Values.queuereader.resources.limits.cpu }}
            cpu: {{ . }}
            {{- end }}
            {{- with .Values.queuereader.resources.limits.memory }}
            memory: {{ . }}
            {{- end }}
          {{- end }}
          {{- if and .Values.queuereader.resources.requests (ne .Values.queuereader.resources.requests.enabled false) }}
          requests:
            {{- with .Values.queuereader.resources.requests.cpu }}
            cpu: {{ . }}
            {{- end }}
            {{- with .Values.queuereader.resources.requests.memory }}
            memory: {{ . }}
            {{- end }}
        {{- end }}
        {{- end }}
        volumeMounts:
          {{- if .Values.databases.datawarehouse.autoCreateSecrets }}
          - name: odbc-config
            mountPath: /app/odbc-config/odbc2.ini
            subPath: odbc2.ini
          {{- end }}
          - name: odbcini
            mountPath: /odbc-config
          - name: tempstore
            mountPath: /tmp
          {{- if .Values.databases.datawarehouse.bigquery.enabled }}
          {{- range .Values.databases.datawarehouse.bigquery.connections }}
          {{- if eq .credentialsType "serviceAccount" }}
          - name: {{ .configMapName | quote }}
            mountPath: {{ .ConfigMapFilePath }}/{{ .keyName }}
            subPath: {{ .keyName }}
            readOnly: true
          {{- end }}
          {{- end }}
          {{- end }}
          {{- if .Values.databases.datawarehouse.snowflake.enabled }}
          {{- if eq .Values.databases.datawarehouse.snowflake.credentialsType "snowflake_jwt" }}
          - name: {{ .Values.databases.datawarehouse.snowflake.ConfigMapName }}
