      tolerations:
        - effect: NoSchedule
          key: {{ .Values.nodeSelector.key }}
          operator: Equal
          value: {{ .Values.nodeSelector.value }}
      {{- end }}
{{- end }}

deploy-rabbitmq.yaml.content:
---
{{- if .Values.queuereader.podDisruptionBudget.enabled }}
apiVersion: policy/v1
kind: PodDisruptionBudget
metadata:
  name: rpi-queuereader-rabbitmq
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-queuereader-rabbitmq
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  maxUnavailable: {{ .Values.queuereader.podDisruptionBudget.maxUnavailable }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-queuereader-rabbitmq
{{- end }}

---
{{- if .Values.queuereader.realtimeConfiguration.isDistributed }}
{{- if eq .Values.queuereader.realtimeConfiguration.distributedQueue.provider "rabbitmq" }}
{{- if eq .Values.queuereader.realtimeConfiguration.distributedQueue.type "internal" }}
apiVersion: v1
kind: ConfigMap
metadata:
  name: rpi-queuereader-rabbitmq-config
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-queuereader-rabbitmq
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
data:
  rabbitmq.conf: |
    # Default RabbitMQ configuration
    listeners.tcp.default = 5672
    management.listener.port = 15672
    loopback_users.guest = false

---
apiVersion: v1
kind: Service
metadata:
  name: rpi-queuereader-rabbitmq
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-queuereader-rabbitmq
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  clusterIP: None
  ports:
    - name: amqp
      port: 5672
      targetPort: 5672
    - name: management
      port: 15672
      targetPort: 15672
  selector:
    app.kubernetes.io/name: rpi-queuereader-rabbitmq

---
apiVersion: apps/v1
kind: StatefulSet
metadata:
  name: rpi-queuereader-rabbitmq
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-queuereader-rabbitmq
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  serviceName: rpi-queuereader-rabbitmq
  persistentVolumeClaimRetentionPolicy:
    whenDeleted: Retain
    whenScaled: Retain
  replicas: 1
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-queuereader-rabbitmq
  template:
    metadata:
      labels:
        app.kubernetes.io/name: rpi-queuereader-rabbitmq
        app.kubernetes.io/instance: {{ .Release.Name }}
        app.kubernetes.io/part-of: rpi
        app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
    spec:
      terminationGracePeriodSeconds: 90
      {{- if .Values.global.deployment.images.imagePullSecret.enabled }}
      imagePullSecrets:
        - name: {{ .Values.global.deployment.images.imagePullSecret.name }}
      {{- end }}
      affinity:
        podAffinity:
          preferredDuringSchedulingIgnoredDuringExecution:
            - weight: 100
              podAffinityTerm:
                labelSelector:
                  matchExpressions:
                    - key: app
                      operator: In
                      values: ["rpi-queuereader"]
                topologyKey: "kubernetes.io/hostname"
        podAntiAffinity:
          preferredDuringSchedulingIgnoredDuringExecution:
            - weight: 100
              podAffinityTerm:
                labelSelector:
                  matchLabels:
                    app.kubernetes.io/name: rpi-queuereader-rabbitmq
                topologyKey: kubernetes.io/hostname
      topologySpreadConstraints:
        - maxSkew: 1
          topologyKey: kubernetes.io/hostname
          whenUnsatisfiable: ScheduleAnyway
          labelSelector:
            matchLabels:
              app.kubernetes.io/name: rpi-queuereader-rabbitmq
      {{- if .Values.nodeSelector.enabled }}
      nodeSelector:
        {{ .Values.nodeSelector.key }}: {{ .Values.nodeSelector.value }}
      {{- end }}
      {{- if .Values.tolerations.enabled }}
      tolerations:
        - effect: NoSchedule
          key: {{ .Values.nodeSelector.key }}
          operator: Equal
          value: {{ .Values.nodeSelector.value }}
      {{- end }}
      containers:
        - name: rpi-queuereader-rabbitmq
          image: {{ .Values.global.deployment.images.rabbitmq }}:{{ .Values.global.deployment.images.tag }}
          imagePullPolicy: {{  .Values.global.deployment.images.imagePullPolicy }}
          ports:
            - name: amqp
              containerPort: 5672
              protocol: TCP
            - name: management
              containerPort: 15672
              protocol: TCP
          {{- if .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.resources.enabled }}
          resources:
            {{- if .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.resources.limits }}
            limits:
              {{- if .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.resources.limits.cpu }}
              cpu: {{ .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.resources.limits.cpu | quote }}
              {{- end }}
              {{- if .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.resources.limits.memory }}
              memory: {{ .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.resources.limits.memory }}
              {{- end }}
            {{- end }}
            {{- if .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.resources.requests }}
            requests:
              {{- if .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.resources.requests.cpu | quote }}
              cpu: {{ .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.resources.requests.cpu }}
              {{- end }}
              {{- if .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.resources.requests.memory }}
              memory: {{ .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.resources.requests.memory }}
              {{- end }}
            {{- end }}
          {{- end }}
          env:
            - name: RABBITMQ_DEFAULT_USER
              value: {{ .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.username | quote }}
            - name: RABBITMQ_DEFAULT_PASS
              valueFrom:
                secretKeyRef:
                  name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
                  key: QueueService_RabbitMQ_Password
            - name: RABBITMQ_DEFAULT_VHOST
              value: {{ .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.virtualhost | quote }}
            - name: RABBITMQ_CONFIG_FILE
              value: "/config/rabbitmq.conf"
          volumeMounts:
            {{- if .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.volumeClaimTemplates.enabled }}
            - name: rpi-queuereader-rabbitmq-data
              mountPath: /data
            {{- end }}
            {{- if not .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.volumeClaimTemplates.enabled }}
            - name: rpi-queuereader-rabbitmq-data
              mountPath: /data
            {{- end }}
            - name: rpi-queuereader-rabbitmq-config
              mountPath: /config
          livenessProbe:
            exec:
              command:
              - "rabbitmq-diagnostics"
              - "-q"
              - "ping"
            initialDelaySeconds: 15
            periodSeconds: 10
            timeoutSeconds: 5
            failureThreshold: 6
          {{- if .Values.securityContext.enabled }}
          securityContext:
            privileged: {{ .Values.securityContext.privileged }}
            allowPrivilegeEscalation: {{ .Values.securityContext.allowPrivilegeEscalation }}
            readOnlyRootFilesystem: {{ .Values.securityContext.readOnlyRootFilesystem }}
            capabilities:
              drop:
              {{- range .Values.securityContext.capabilities.drop }}
                - {{ . }}
              {{- end }}
          {{- end }}
      {{- if .Values.securityContext.enabled }}
      securityContext:
        runAsUser: {{ .Values.securityContext.runAsUser }}
        runAsGroup: {{ .Values.securityContext.runAsGroup }}
        runAsNonRoot: {{ .Values.securityContext.runAsNonRoot }}
      {{- end }}
      volumes:
        - name: rpi-queuereader-rabbitmq-config
          configMap:
            name: rpi-queuereader-rabbitmq-config
        {{- if not .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.volumeClaimTemplates.enabled }}
        - name: rpi-queuereader-rabbitmq-data
          emptyDir: {}
        {{- end }}
  {{- if .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.volumeClaimTemplates.enabled }}
  volumeClaimTemplates:
    - metadata:
        name: rpi-queuereader-rabbitmq-data
      spec:
        accessModes: ["ReadWriteOnce"]
        resources:
          requests:
            storage: {{ .Values.queuereader.realtimeConfiguration.distributedQueue.rabbitmqSettings.volumeClaimTemplates.storage | quote }}
  {{- end }}
{{- end }}
{{- end }}
{{- end }}


