              secretKeyRef:
                name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
                key: RealtimeAPI_QueueSettings_SecretKey
          {{- end }}
          {{- end }}
          - name: RealtimeAPIConfiguration__Queues__ListenerQueueSettings__Settings__9__Key
