apiVersion: v1
kind: ServiceAccount
metadata:
  name: rpi-executionservice-cache
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-executionservice-cache
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}

---
apiVersion: apps/v1
kind: StatefulSet
metadata:
  name: rpi-executionservice-cache
  namespace: {{ .Release.Namespace }}
  labels:
    app.kubernetes.io/name: rpi-executionservice-cache
    app.kubernetes.io/instance: {{ .Release.Name }}
    app.kubernetes.io/part-of: rpi
    app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
spec:
  serviceName: rpi-executionservice-cache
  persistentVolumeClaimRetentionPolicy:
    whenDeleted: Retain
    whenScaled: Retain
  replicas: {{ .Values.executionservice.internalCache.redisSettings.replicas }}
  selector:
    matchLabels:
      app.kubernetes.io/name: rpi-executionservice-cache
  template:
    metadata:
      labels:
        app.kubernetes.io/name: rpi-executionservice-cache
        app.kubernetes.io/instance: {{ .Release.Name }}
        app.kubernetes.io/part-of: rpi
        app.kubernetes.io/version: {{ .Values.global.deployment.images.tag | quote }}
    spec:
      {{- if .Values.global.deployment.images.imagePullSecret.enabled }}
      imagePullSecrets:
        - name: {{ .Values.global.deployment.images.imagePullSecret.name }}
      {{- end }}
      affinity:
        podAffinity:
          preferredDuringSchedulingIgnoredDuringExecution:
            - weight: 100
              podAffinityTerm:
                labelSelector:
                  matchExpressions:
                    - key: app
                      operator: In
                      values: ["rpi-executionservice"]
                topologyKey: "kubernetes.io/hostname"
        podAntiAffinity:
          preferredDuringSchedulingIgnoredDuringExecution:
            - weight: 100
              podAffinityTerm:
                labelSelector:
                  matchLabels:
                    app.kubernetes.io/name: rpi-executionservice-cache
                topologyKey: kubernetes.io/hostname
      topologySpreadConstraints:
        - maxSkew: 1
          topologyKey: kubernetes.io/hostname
          whenUnsatisfiable: ScheduleAnyway
          labelSelector:
            matchLabels:
              app.kubernetes.io/name: rpi-executionservice-cache
      {{- if .Values.nodeSelector.enabled }}
      nodeSelector:
        {{ .Values.nodeSelector.key }}: {{ .Values.nodeSelector.value }}
      {{- end }}
      {{- if .Values.tolerations.enabled }}
      tolerations:
        - effect: NoSchedule
          key: {{ .Values.nodeSelector.key }}
          operator: Equal
          value: {{ .Values.nodeSelector.value }}
      {{- end }}
      containers:
        - name: rpi-executionservice-cache
          image: {{ .Values.global.deployment.images.rediscache }}:{{ .Values.global.deployment.images.tag }}
          imagePullPolicy: {{ .Values.global.deployment.images.imagePullPolicy }}
          ports:
            - containerPort: 6379
              name: redis
          {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
          command: ["redis-server", "/usr/local/etc/redis/redis.conf", "--requirepass", "$(REDIS_PASSWORD)"]
          {{- end }}
          {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "keyvault" }}
          command: ["redis-server", "/usr/local/etc/redis/redis.conf"]
          {{- end }}
          {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
          command: ["redis-server", "/usr/local/etc/redis/redis.conf"]
          {{- end }}
          env:
          {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
          - name: REDIS_PASSWORD
            valueFrom:
              secretKeyRef:
                name: {{ .Values.cloudIdentity.secretsManagement.secretName | quote }}
                key: ExecutionService_RedisCache_Password
          {{- end }}
          volumeMounts:
            {{- if .Values.executionservice.internalCache.redisSettings.volumeClaimTemplates.enabled }}
            - name: rpi-executionservice-cache-data
              mountPath: /data
            {{- end }}
            {{- if not .Values.executionservice.internalCache.redisSettings.volumeClaimTemplates.enabled }}
            - name: rpi-executionservice-cache-data
              mountPath: /data
            {{- end }}
            - name: rpi-executionservice-cache-config
              mountPath: /usr/local/etc/redis
          {{- if .Values.executionservice.internalCache.redisSettings.resources.enabled }}
          resources:
            {{- if .Values.executionservice.internalCache.redisSettings.resources.limits }}
            limits:
              {{- if .Values.executionservice.internalCache.redisSettings.resources.limits.cpu }}
              cpu: {{ .Values.executionservice.internalCache.redisSettings.resources.limits.cpu | quote }}
              {{- end }}
              {{- if .Values.executionservice.internalCache.redisSettings.resources.limits.memory }}
              memory: {{ .Values.executionservice.internalCache.redisSettings.resources.limits.memory }}
              {{- end }}
            {{- end }}
            {{- if .Values.executionservice.internalCache.redisSettings.resources.requests }}
            requests:
              {{- if .Values.executionservice.internalCache.redisSettings.resources.requests.cpu | quote }}
              cpu: {{ .Values.executionservice.internalCache.redisSettings.resources.requests.cpu }}
              {{- end }}
              {{- if .Values.executionservice.internalCache.redisSettings.resources.requests.memory }}
              memory: {{ .Values.executionservice.internalCache.redisSettings.resources.requests.memory }}
              {{- end }}
            {{- end }}
          {{- end }}
          readinessProbe:
            exec:
              {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
              command: ["sh", "-c", "redis-cli -a \"$REDIS_PASSWORD\" ping | grep PONG"]
              {{- end }}
              {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "keyvault" }}
              command: ["sh", "-c", "redis-cli ping | grep PONG"]
              {{- end }}
              {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
              command: ["sh", "-c", "redis-cli ping | grep PONG"]
              {{- end }}
            initialDelaySeconds: 5
            periodSeconds: 5
            timeoutSeconds: 2
            failureThreshold: 6
          livenessProbe:
            exec:
              {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "kubernetes" }}
              command: ["sh", "-c", "redis-cli -a \"$REDIS_PASSWORD\" ping | grep PONG"]
              {{- end }}
              {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "keyvault" }}
              command: ["sh", "-c", "redis-cli ping | grep PONG"]
              {{- end }}
              {{- if eq .Values.cloudIdentity.secretsManagement.secretsProvider "awssecretsmanager" }}
              command: ["sh", "-c", "redis-cli ping | grep PONG"]
              {{- end }}
            initialDelaySeconds: 15
            periodSeconds: 10
            timeoutSeconds: 3
            failureThreshold: 3
          {{- if .Values.securityContext.enabled }}
          securityContext:
            privileged: {{ .Values.securityContext.privileged }}
            allowPrivilegeEscalation: {{ .Values.securityContext.allowPrivilegeEscalation }}
            readOnlyRootFilesystem: {{ .Values.securityContext.readOnlyRootFilesystem }}
            capabilities:
              drop:
              {{- range .Values.securityContext.capabilities.drop }}
                - {{ . }}
              {{- end }}
          {{- end }}
      {{- if .Values.securityContext.enabled }}
      securityContext:
        runAsUser: {{ .Values.securityContext.runAsUser }}
        runAsGroup: {{ .Values.securityContext.runAsGroup }}
        fsGroup: {{ .Values.securityContext.fsGroup }}
        runAsNonRoot: {{ .Values.securityContext.runAsNonRoot }}
        supplementalGroups:
          {{- with .Values.securityContext.supplementalGroups }}
          {{- toYaml . | nindent 10 }}
          {{- end }}
      {{- end }}
      volumes:
        - name: rpi-executionservice-cache-config
          configMap:
            name: rpi-executionservice-cache-config
        {{- if not .Values.executionservice.internalCache.redisSettings.volumeClaimTemplates.enabled }}
        - name: rpi-executionservice-cache-data
          emptyDir: {}
        {{- end }}
  {{- if .Values.executionservice.internalCache.redisSettings.volumeClaimTemplates.enabled }}
  volumeClaimTemplates:
    - metadata:
        name: rpi-executionservice-cache-data
      spec:
        accessModes: ["ReadWriteOnce"]
        resources:
          requests:
            storage: {{ .Values.executionservice.internalCache.redisSettings.volumeClaimTemplates.storage | quote }}
  {{- end }}
{{- end }}
{{- end }}
{{- end }}

